#![no_std]

pub mod arch;
pub mod console;
pub mod efi;
pub mod fdt;
pub mod memory;
pub mod paging;
pub mod trap;

pub use arch::{
    ArchBoot, ArchConsole, ArchCpu, ArchPaging, ArchPlatform, ArchTimer, ArchTrap, ArchUser,
    ArchUserPaging, KernelArch, MmioRegion, UserContext, UserMapFlags, UserPageMapping,
    UserPagingError, idle_loop,
};
pub use console::EarlyConsole;
pub use trap::{ExceptionKind, InterruptKind, TrapCause, TrapFrame, UserTrapContext, USER_TRAP_FRAME_WORDS};

pub const TEST_GROUP_START_PREFIX: &str = "#### OS COMP TEST GROUP START ";
pub const TEST_GROUP_END_PREFIX: &str = "#### OS COMP TEST GROUP END ";

pub const BOOT_INFO_MAGIC: u64 = 0x4c55_5755_424f_4f54;
pub const BOOT_INFO_VERSION: u32 = 1;
pub const BOOT_MEMORY_REGIONS_MAX: usize = 32;

// 启动阶段收集到的物理内存用途。后面的 MemoryMap 只会从 Usable 里分配，
// 其他类型都作为保留区扣掉，避免 page table 或未来 allocator 覆盖固件/内核。
#[repr(u32)]
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum BootMemoryKind {
    Unknown = 0,
    Usable = 1,
    Reserved = 2,
    Acpi = 3,
    Mmio = 4,
    Bootloader = 5,
    Kernel = 6,
}

#[repr(C)]
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct BootMemoryRegion {
    // 半开物理区间：[start, start + len)。
    pub start: u64,
    pub len: u64,
    pub kind: BootMemoryKind,
    // 留给以后扩展 flag，同时保持 C ABI 对齐稳定。
    pub _reserved: u32,
}

// entry.S 和 Rust 之间的启动 ABI。字段顺序和大小不能随手改；
// 如果要改布局，需要同步 docs/bootloader.md、两个 entry.S 和 BOOT_INFO_VERSION。
#[repr(C)]
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct BootInfo {
    pub magic: u64,
    pub version: u32,
    pub memory_region_count: u32,
    pub arg0: u64,
    pub arg1: u64,
    pub arg2: u64,
    pub kernel_start: usize,
    pub kernel_end: usize,
    pub boot_stack_start: usize,
    pub boot_stack_end: usize,
    pub fdt_addr: usize,
    pub efi_system_table: usize,
    pub memory_regions: [BootMemoryRegion; BOOT_MEMORY_REGIONS_MAX],
}

impl BootInfo {
    #[inline]
    pub const fn is_valid(&self) -> bool {
        self.magic == BOOT_INFO_MAGIC && self.version == BOOT_INFO_VERSION
    }

    #[inline]
    pub const fn memory_regions(&self) -> &[BootMemoryRegion] {
        // 汇编或坏 bootloader 可能写出越界 count。这里裁剪到数组容量，
        // 后续代码只遍历这个安全 slice。
        let count = if self.memory_region_count as usize > BOOT_MEMORY_REGIONS_MAX {
            BOOT_MEMORY_REGIONS_MAX
        } else {
            self.memory_region_count as usize
        };
        let regions = &self.memory_regions;
        unsafe { core::slice::from_raw_parts(regions.as_ptr(), count) }
    }

    #[inline]
    pub fn clear_memory_regions(&mut self) {
        self.memory_region_count = 0;
    }

    #[inline]
    pub fn add_memory_region(&mut self, start: u64, len: u64, kind: BootMemoryKind) -> bool {
        // 早期不分配内存，BootInfo 里的固定数组就是唯一记录空间；
        // 写不下时返回 false，让调用者可以继续用已收集到的布局启动。
        if len == 0 || self.memory_region_count as usize >= BOOT_MEMORY_REGIONS_MAX {
            return false;
        }

        let index = self.memory_region_count as usize;
        self.memory_regions[index] = BootMemoryRegion {
            start,
            len,
            kind,
            _reserved: 0,
        };
        self.memory_region_count += 1;
        true
    }

    #[inline]
    pub fn reserve_boot_regions(&mut self) {
        self.reserve_boot_regions_with_offset(0);
    }

    #[inline]
    pub fn reserve_boot_regions_with_offset(&mut self, virt_phys_offset: usize) {
        // LoongArch 当前从 DMW0 高地址运行，BootInfo 里记录的是虚拟地址；
        // frame allocator 只处理物理地址，所以这里允许调用者传入固定偏移做转换。
        let kernel_start = self.kernel_start.saturating_sub(virt_phys_offset);
        let kernel_end = self.kernel_end.saturating_sub(virt_phys_offset);
        let stack_start = self.boot_stack_start.saturating_sub(virt_phys_offset);
        let stack_end = self.boot_stack_end.saturating_sub(virt_phys_offset);
        let boot_info_start = (self as *const Self as usize).saturating_sub(virt_phys_offset);
        let boot_info_end = boot_info_start + core::mem::size_of::<Self>();
        let kernel_len = kernel_end.saturating_sub(kernel_start);
        let stack_len = stack_end.saturating_sub(stack_start);

        self.add_memory_region(
            kernel_start as u64,
            kernel_len as u64,
            BootMemoryKind::Kernel,
        );
        self.add_memory_region(
            stack_start as u64,
            stack_len as u64,
            BootMemoryKind::Bootloader,
        );
        self.add_memory_region(
            boot_info_start as u64,
            (boot_info_end - boot_info_start) as u64,
            BootMemoryKind::Bootloader,
        );
    }
}

#[inline]
pub fn spin_forever() -> ! {
    loop {
        core::hint::spin_loop();
    }
}

use crate::{paging::PAGE_SIZE, BootInfo, EarlyConsole, UserTrapContext};

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct MmioRegion {
    pub base: usize,
    pub size: usize,
}

pub trait ArchBoot {
    // 打印用的架构名，也能帮助确认当前 binary 真的进了哪个 arch crate。
    const NAME: &'static str;

    // Rust 入口最早调用这里。entry.S 只准备最低限度的启动环境，
    // 这里负责把架构启动参数继续整理成 common BootInfo，例如解析 FDT/EFI。
    fn early_init(boot_info: &mut BootInfo);
}

pub trait ArchCpu {
    // 内核暂时没有调度器，阻塞等待和 idle 都落到架构自己的省电/等中断指令。
    fn wait_for_interrupt();

    // 这两个接口先服务 QEMU console 命令，真机启动时可以替换成平台复位路径。
    fn reboot() -> !;

    fn poweroff() -> !;
}

pub trait ArchConsole {
    // 早期 console 不能依赖堆、驱动模型或中断，所以每次都返回一个轻量句柄。
    // 这个句柄通常只是 MMIO/SBI 端口地址的零大小封装。
    type Console: EarlyConsole;

    fn early_console() -> Self::Console;
}

pub trait ArchPaging {
    // 使用 BootInfo 里的物理内存布局建立最早的内核页表。
    // 现在只保证 kernel、stack、BootInfo 和 QEMU 必需 MMIO 能继续访问。
    fn init_kernel_page_table(boot_info: &BootInfo);
}

pub trait ArchTrap {
    // 写架构 trap vector CSR，之后中断/异常会先进入 arch crate 的汇编入口。
    fn init_trap();

    // 把架构原始 cause/estat/scause 解码成 common 的 TrapCause，
    // 这样 kernel trap 分发不用到处写架构编号。
    fn decode_trap_cause(raw_cause: usize) -> crate::TrapCause;

    fn trap_from_user(frame: &crate::TrapFrame) -> bool;

    // 从 trap 保存现场里提取 syscall 号和参数。
    fn decode_syscall_number(frame: &crate::TrapFrame) -> usize;

    fn decode_syscall_args(frame: &crate::TrapFrame) -> [usize; 6];

    fn decode_clone_extra_args(args: [usize; 6]) -> (usize, usize, usize);

    // 把 syscall 返回值写回保存现场，并推进返回地址。
    fn write_syscall_return(frame: &crate::TrapFrame, value: isize);

    fn advance_syscall_epc(frame: &crate::TrapFrame, bytes: usize);

    // 进程调度使用这些接口复制/恢复用户态现场，并修改架构相关的返回值/栈/TLS 寄存器。
    fn capture_user_context(frame: &crate::TrapFrame, page_table_root: usize) -> UserTrapContext;

    fn set_context_return_value(context: &mut UserTrapContext, value: usize);

    fn set_context_stack_pointer(context: &mut UserTrapContext, stack: usize);

    fn set_context_thread_pointer(context: &mut UserTrapContext, thread_pointer: usize);

    fn resume_user(context: &UserTrapContext) -> !;

    // sys_exit 之后回到内核态继续执行脚本/调度逻辑。
    fn resume_to_kernel(kernel_epc: usize);
}

pub trait ArchTimer {
    // 打开最早的周期 timer interrupt。当前只用它验证 trap path 和 idle 唤醒。
    fn init_timer();

    // 统一 trap handler 识别到 timer 后回调这里清中断/重装下一次 tick。
    fn handle_timer_interrupt();

    fn monotonic_time_nanos() -> u64;
}

pub trait ArchPlatform {
    fn virtio_mmio_regions(out: &mut [MmioRegion]) -> usize;

    fn pci_ecam_base() -> Option<usize> {
        None
    }

    fn pci_mmio32_base() -> Option<usize> {
        None
    }

    fn virt_to_phys(addr: usize) -> usize;

    fn phys_to_virt(addr: usize) -> usize;

    fn dma_virt_to_virt(addr: usize) -> usize {
        addr
    }

    fn dma_fence();

    fn tlb_flush() {
        Self::dma_fence();
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct UserContext {
    pub entry: usize,
    pub stack_top: usize,
    pub page_table_root: usize,
    pub argc: usize,
    pub argv: usize,
    pub envp: usize,
    pub tls: usize,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct UserPageMapping {
    pub va: usize,
    pub pa: usize,
    pub flags: UserMapFlags,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct UserMapFlags {
    bits: u8,
}

impl UserMapFlags {
    pub const READ: Self = Self { bits: 1 << 0 };
    pub const WRITE: Self = Self { bits: 1 << 1 };
    pub const EXECUTE: Self = Self { bits: 1 << 2 };
    pub const USER: Self = Self { bits: 1 << 3 };

    pub const fn empty() -> Self {
        Self { bits: 0 }
    }

    pub const fn bits(self) -> u8 {
        self.bits
    }

    pub const fn contains(self, flags: Self) -> bool {
        self.bits & flags.bits == flags.bits
    }

    pub const fn union(self, flags: Self) -> Self {
        Self {
            bits: self.bits | flags.bits,
        }
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum UserPagingError {
    Unsupported,
    OutOfMemory,
    InvalidAddress,
}

pub trait ArchUserPaging {
    fn create_user_root() -> Result<usize, UserPagingError>;

    fn map_user_page(root: usize, mapping: UserPageMapping) -> Result<(), UserPagingError>;

    fn share_kernel_mappings(root: usize, boot_info: &BootInfo) -> Result<(), UserPagingError> {
        let _ = root;
        let _ = boot_info;
        Ok(())
    }

    fn user_page_size() -> usize {
        PAGE_SIZE
    }
}

pub trait ArchUser {
    fn enter_user(context: &UserContext);
}

pub trait KernelArch:
    ArchBoot + ArchCpu + ArchConsole + ArchPaging + ArchTrap + ArchTimer + ArchPlatform
{
}

impl<T> KernelArch for T where
    T: ArchBoot + ArchCpu + ArchConsole + ArchPaging + ArchTrap + ArchTimer + ArchPlatform
{
}

#[inline]
pub fn idle_loop<A: ArchCpu>() -> ! {
    loop {
        A::wait_for_interrupt();
    }
}

