pub const MEMORY_RANGES_MAX: usize = BOOT_MEMORY_REGIONS_MAX * 2;
pub const RECYCLED_FRAMES_MAX: usize = 65536;
const LOW_MEMORY_RESERVE_END: u64 = 0x10_0000;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum MemoryMapError {
    TooManyRanges,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct PhysRange {
    // 半开物理区间：[start, end)。end 不可访问，方便做长度和相交计算。
    pub start: usize,
    pub end: usize,
}

impl PhysRange {
    #[inline]
    pub const fn len(&self) -> usize {
        self.end - self.start
    }

    #[inline]
    pub const fn is_empty(&self) -> bool {
        self.start >= self.end
    }
}

pub struct MemoryMap {
    // usable 是已经扣完 reserved 且按页对齐后的可分配物理范围。
    // reserved 保留原始保留区，只用来从 usable 里裁剪，不直接参与分配。
    usable: [PhysRange; MEMORY_RANGES_MAX],
    usable_count: usize,
    reserved: [PhysRange; BOOT_MEMORY_REGIONS_MAX],
    reserved_count: usize,
}

impl MemoryMap {
    #[inline]
    pub const fn new() -> Self {
        const EMPTY: PhysRange = PhysRange { start: 0, end: 0 };

        Self {
            usable: [EMPTY; MEMORY_RANGES_MAX],
            usable_count: 0,
            reserved: [EMPTY; BOOT_MEMORY_REGIONS_MAX],
            reserved_count: 0,
        }
    }

    pub fn from_boot_info(boot_info: &BootInfo) -> Result<Self, MemoryMapError> {
        let mut map = Self::new();

        // BootInfo 里是“平台报告 + 内核追加”的原始记录，可能互相重叠。
        // 先把 Usable 和非 Usable 分桶，后面再统一从 Usable 中扣掉保留区。
        for region in boot_info.memory_regions() {
            match region.kind {
                BootMemoryKind::Usable => map.push_usable(region)?,
                BootMemoryKind::Unknown => {}
                _ => map.push_reserved(region)?,
            }
        }

        // 低 1MiB 暂时保守保留。x86 传统 BIOS 区不是这里的目标，
        // 但低地址经常被固件表、异常向量或平台 MMIO 占用；早期先不从这里分配。
        map.push_reserved_range(PhysRange {
            start: 0,
            end: LOW_MEMORY_RESERVE_END as usize,
        })?;
        // 规范化顺序：扣 reserved -> 页对齐 -> 排序。
        // 排序后 frame allocator 可以按地址稳定地线性分配。
        map.subtract_reserved()?;
        map.sort_usable();
        Ok(map)
    }

    #[inline]
    pub fn usable_ranges(&self) -> &[PhysRange] {
        &self.usable[..self.usable_count]
    }

    #[inline]
    pub fn reserved_ranges(&self) -> &[PhysRange] {
        &self.reserved[..self.reserved_count]
    }

    #[inline]
    pub fn total_usable_bytes(&self) -> usize {
        let mut total = 0usize;
        for range in self.usable_ranges() {
            total = total.saturating_add(range.len());
        }
        total
    }

    fn push_usable(&mut self, region: &BootMemoryRegion) -> Result<(), MemoryMapError> {
        let Some(range) = usable_range(region) else {
            return Ok(());
        };
        self.push_usable_range(range)
    }

    fn push_reserved(&mut self, region: &BootMemoryRegion) -> Result<(), MemoryMapError> {
        let Some(range) = raw_range(region) else {
            return Ok(());
        };
        self.push_reserved_range(range)
    }

    fn push_usable_range(&mut self, range: PhysRange) -> Result<(), MemoryMapError> {
        if range.is_empty() {
            return Ok(());
        }
        if self.usable_count >= self.usable.len() {
            return Err(MemoryMapError::TooManyRanges);
        }
        self.usable[self.usable_count] = range;
        self.usable_count += 1;
        Ok(())
    }

    fn push_reserved_range(&mut self, range: PhysRange) -> Result<(), MemoryMapError> {
        if range.is_empty() {
            return Ok(());
        }
        if self.reserved_count >= self.reserved.len() {
            return Err(MemoryMapError::TooManyRanges);
        }
        self.reserved[self.reserved_count] = range;
        self.reserved_count += 1;
        Ok(())
    }

    fn subtract_reserved(&mut self) -> Result<(), MemoryMapError> {
        let mut reserved_index = 0usize;
        while reserved_index < self.reserved_count {
            let reserved = self.reserved[reserved_index];
            let mut usable_index = 0usize;

            while usable_index < self.usable_count {
                let usable = self.usable[usable_index];
                if reserved.end <= usable.start || reserved.start >= usable.end {
                    usable_index += 1;
                    continue;
                }

                // reserved 命中 usable 中间时，会把一段 usable 切成左右两段。
                // 两段都重新按页对齐，避免 allocator 交出半页或跨保留区的 frame。
                let left = align_usable_range(PhysRange {
                    start: usable.start,
                    end: core::cmp::min(reserved.start, usable.end),
                });
                let right = align_usable_range(PhysRange {
                    start: core::cmp::max(reserved.end, usable.start),
                    end: usable.end,
                });

                self.remove_usable(usable_index);
                // remove_usable 会把最后一个元素换到当前 index。
                // 这里不递增 usable_index，下一轮会继续检查换进来的范围。
                if let Some(right) = right {
                    self.push_usable_range(right)?;
                }
                if let Some(left) = left {
                    self.push_usable_range(left)?;
                }
            }

            reserved_index += 1;
        }

        Ok(())
    }

    fn remove_usable(&mut self, index: usize) {
        self.usable_count -= 1;
        self.usable[index] = self.usable[self.usable_count];
    }

    fn sort_usable(&mut self) {
        let len = self.usable_count;
        let mut i = 1usize;
        while i < len {
            let mut j = i;
            while j > 0 && self.usable[j - 1].start > self.usable[j].start {
                self.usable.swap(j - 1, j);
                j -= 1;
            }
            i += 1;
        }
    }
}

