use core::arch::asm;

use luwu_kernel::{
    BootInfo, UserMapFlags, UserPageMapping, UserPagingError, memory,
    paging::{PAGE_SIZE, align_down},
};

const PAGE_TABLE_ENTRIES: usize = 512;
const PTE_V: usize = 1 << 0;
const PTE_R: usize = 1 << 1;
const PTE_W: usize = 1 << 2;
const PTE_X: usize = 1 << 3;
const PTE_U: usize = 1 << 4;
const PTE_A: usize = 1 << 6;
const PTE_D: usize = 1 << 7;
const SATP_MODE_SV39: usize = 8 << 60;
const GIB: usize = 1 << 30;

#[repr(C, align(4096))]
struct PageTable {
    entries: [usize; PAGE_TABLE_ENTRIES],
}

pub fn init_sv39(boot_info: &BootInfo) {
    let kernel_base = align_down(boot_info.kernel_start);
    let uart_base = align_down(0x1000_0000);
    let Some(root_frame) = memory::alloc_zeroed_frame::<crate::Riscv64>() else {
        panic!("riscv: failed to allocate root page table");
    };
    let root = root_frame as *mut PageTable;

    unsafe {
        // 早期内核仍使用 1GiB 大页映射，用户地址空间后续使用独立 4KiB 页表。
        map_gib_page(root, uart_base);
        map_gib_page(root, kernel_base);

        let root_ppn = root_frame >> 12;
        asm!(
            "csrw satp, {satp}",
            "sfence.vma",
            satp = in(reg) (SATP_MODE_SV39 | root_ppn),
            options(nostack)
        );
    }
}

pub fn create_user_root() -> Result<usize, UserPagingError> {
    memory::alloc_zeroed_frame::<crate::Riscv64>().ok_or(UserPagingError::OutOfMemory)
}

pub fn share_kernel_mappings(root_frame: usize, boot_info: &BootInfo) -> Result<(), UserPagingError> {
    let root = root_frame as *mut PageTable;
    unsafe {
        // 用户页表也要能取到 supervisor trap/kernel 代码和必要 MMIO；PTE_U 不置位。
        map_gib_page(root, align_down(boot_info.kernel_start));
        map_4k_page(root, align_down(0x1000_0000), align_down(0x1000_0000), kernel_leaf_flags())?;
        for index in 0..8 {
            let mmio = 0x1000_1000 + index * PAGE_SIZE;
            map_4k_page(root, mmio, mmio, kernel_leaf_flags())?;
        }
    }
    Ok(())
}

pub fn map_user_page(root_frame: usize, mapping: UserPageMapping) -> Result<(), UserPagingError> {
    if mapping.va % PAGE_SIZE != 0 || mapping.pa % PAGE_SIZE != 0 {
        return Err(UserPagingError::InvalidAddress);
    }

    let root = root_frame as *mut PageTable;
    let vpn2 = (mapping.va >> 30) & 0x1ff;
    let vpn1 = (mapping.va >> 21) & 0x1ff;
    let vpn0 = (mapping.va >> 12) & 0x1ff;

    unsafe {
        let level1 = ensure_next_table(root, vpn2)?;
        let level0 = ensure_next_table(level1, vpn1)?;
        let pte = ((mapping.pa >> 12) << 10) | pte_flags(mapping.flags);
        core::ptr::write_volatile(core::ptr::addr_of_mut!((*level0).entries[vpn0]), pte);
    }
    Ok(())
}

pub fn user_satp(root_frame: usize) -> usize {
    SATP_MODE_SV39 | (root_frame >> 12)
}

unsafe fn ensure_next_table(
    table: *mut PageTable,
    index: usize,
) -> Result<*mut PageTable, UserPagingError> {
    let entry = unsafe { core::ptr::read_volatile(core::ptr::addr_of!((*table).entries[index])) };
    if entry & PTE_V != 0 {
        let pa = (entry >> 10) << 12;
        return Ok(pa as *mut PageTable);
    }

    let frame = memory::alloc_zeroed_frame::<crate::Riscv64>().ok_or(UserPagingError::OutOfMemory)?;
    let pte = ((frame >> 12) << 10) | PTE_V;
    unsafe {
        core::ptr::write_volatile(core::ptr::addr_of_mut!((*table).entries[index]), pte);
    }
    Ok(frame as *mut PageTable)
}

fn pte_flags(flags: UserMapFlags) -> usize {
    let mut pte = PTE_V | PTE_A | PTE_D;
    if flags.contains(UserMapFlags::READ) {
        pte |= PTE_R;
    }
    if flags.contains(UserMapFlags::WRITE) {
        pte |= PTE_W;
    }
    if flags.contains(UserMapFlags::EXECUTE) {
        pte |= PTE_X;
    }
    if flags.contains(UserMapFlags::USER) {
        pte |= PTE_U;
    }
    pte
}

unsafe fn map_4k_page(
    root: *mut PageTable,
    va: usize,
    pa: usize,
    flags: usize,
) -> Result<(), UserPagingError> {
    let vpn2 = (va >> 30) & 0x1ff;
    let vpn1 = (va >> 21) & 0x1ff;
    let vpn0 = (va >> 12) & 0x1ff;
    let level1 = unsafe { ensure_next_table(root, vpn2)? };
    let level0 = unsafe { ensure_next_table(level1, vpn1)? };
    let pte = ((pa >> 12) << 10) | flags;
    unsafe {
        core::ptr::write_volatile(core::ptr::addr_of_mut!((*level0).entries[vpn0]), pte);
    }
    Ok(())
}

fn kernel_leaf_flags() -> usize {
    PTE_V | PTE_R | PTE_W | PTE_X | PTE_A | PTE_D
}

unsafe fn map_gib_page(root: *mut PageTable, addr: usize) {
    let base = addr & !(GIB - 1);
    let index = (base >> 30) & 0x1ff;
    let pte = ((base >> 12) << 10) | PTE_V | PTE_R | PTE_W | PTE_X | PTE_A | PTE_D;
    unsafe {
        core::ptr::write_volatile(core::ptr::addr_of_mut!((*root).entries[index]), pte);
    }
}

use core::arch::asm;

use luwu_kernel::{
    KernelArch,
    trap::{ExceptionKind, InterruptKind, TrapCause, TrapFrame, handle_trap as handle_kernel_trap},
};

pub fn init() {
    unsafe extern "C" {
        static __riscv_trap_vector: u8;
    }

    // stvec 使用 Direct 模式：所有 S-mode trap 先进入同一个汇编入口，
    // 汇编只采集 CSR 和最小寄存器现场，具体分类交给统一 TrapCause。
    let vector = core::ptr::addr_of!(__riscv_trap_vector) as usize;
    unsafe {
        asm!(
            "csrw stvec, {vector}",
            "csrw sscratch, zero",
            vector = in(reg) vector,
            options(nostack)
        );
    }
}

pub fn handle_trap<A: KernelArch + luwu_kernel::ArchUserPaging + luwu_kernel::ArchUser + 'static>(
    scause: usize,
    sepc: usize,
    stval: usize,
    sstatus: usize,
    frame: usize,
) {
    let _ = (sepc, stval, sstatus);
    handle_kernel_trap::<A>(TrapFrame {
        raw_cause: scause,
        epc: sepc,
        badv: stval,
        status: sstatus,
        saved_frame: frame,
    });
}

pub fn decode_trap_cause(scause: usize) -> TrapCause {
    let is_interrupt = (scause >> (usize::BITS as usize - 1)) != 0;
    let code = scause & !(1usize << (usize::BITS as usize - 1));

    if is_interrupt {
        TrapCause::Interrupt(match code {
            1 => InterruptKind::SupervisorSoftware,
            5 => InterruptKind::SupervisorTimer,
            9 => InterruptKind::SupervisorExternal,
            _ => InterruptKind::Unknown { code },
        })
    } else {
        TrapCause::Exception(match code {
            0 => ExceptionKind::InstructionAddressMisaligned,
            1 => ExceptionKind::InstructionAccessFault,
            2 => ExceptionKind::IllegalInstruction,
            3 => ExceptionKind::Breakpoint,
            4 => ExceptionKind::LoadAddressMisaligned,
            5 => ExceptionKind::LoadAccessFault,
            6 => ExceptionKind::StoreAddressMisaligned,
            7 => ExceptionKind::StoreAccessFault,
            8 => ExceptionKind::UserEnvCall,
            9 => ExceptionKind::SupervisorEnvCall,
            12 => ExceptionKind::InstructionPageFault,
            13 => ExceptionKind::LoadPageFault,
            15 => ExceptionKind::StorePageFault,
            _ => ExceptionKind::Unknown { code, subcode: 0 },
        })
    }
}

