use core::arch::asm;

use luwu_kernel::{
    memory, paging::align_down, BootInfo, UserMapFlags, UserPageMapping, UserPagingError,
};

const PAGE_TABLE_ENTRIES: usize = 512;

// LoongArch 4KiB leaf PTE 关键位：
// - V/D/P/W/G/MAT/NX 这些位决定是否存在、是否可写、缓存属性和执行属性；
// - PLV 决定最低可访问特权级，用户页必须给到 PLV3；
// - 目录项不是 leaf，不得混入权限位，只能放下一级页表物理地址。
const PTE_V: usize = 1 << 0;
const PTE_D: usize = 1 << 1;
const PTE_PLV_USER: usize = 0b11 << 2;
const PTE_PLV_KERNEL: usize = 0b00 << 2;
const PTE_MAT_SUC: usize = 0 << 4;
const PTE_MAT_CC: usize = 1 << 4;
const PTE_G: usize = 1 << 6;
const PTE_PRESENT: usize = 1 << 7;
const PTE_WRITE: usize = 1 << 8;
const PTE_NR: usize = 1 << 61;
const PTE_NX: usize = 1 << 62;
const PA_MASK_48: usize = 0x0000_ffff_ffff_f000;
const DMW0_PHYS_OFFSET: usize = 0x9000_0000_0000_0000;
const DMW0_PLV0_CC_VSEG9: usize = DMW0_PHYS_OFFSET | 0x11;
const DMW1_PLV0_SUC_VSEG8: usize = 0x8000_0000_0000_0001;
const UART0: usize = 0x1fe0_01e0;
const ACPI_GED_BASE: usize = 0x100e_0000;
const PCIE_ECAM_BASE: usize = 0x2000_0000;
const PCIE_ECAM_SIZE: usize = 0x0010_0000;
const PCIE_MMIO32_BASE: usize = 0x4000_0000;
const PCIE_MMIO32_SIZE: usize = 0x0100_0000;

// 这一版把页表收敛成统一的 3 级 4KiB walk：
// - 内核低地址 MMIO 继续走页表；
// - 用户页表也复用同一套层级，方便后续从同一套 ArchUserPaging 接口进入用户态。
//
//   dir2_index = va[38:30]
//   dir1_index = va[29:21]
//   pte_index  = va[20:12]
#[repr(C, align(4096))]
struct PageTable {
    entries: [usize; PAGE_TABLE_ENTRIES],
}

pub fn init_la64_page_table(boot_info: &BootInfo) {
    unsafe extern "C" {
        static __loongarch_tlb_refill: u8;
    }

    // 早期页表页来自 frame allocator；这里直接拿物理页做根表。
    let Some(root_frame) = memory::alloc_zeroed_frame::<crate::LoongArch64>() else {
        panic!("loongarch: failed to allocate root page table");
    };
    let root = phys_to_virt(root_frame) as *mut PageTable;

    unsafe {
        // 低地址 UART/ACPI GED 仍然走页表，这样调试串口和关机路径都保持一致。
        map_leaf_page(root, UART0, UART0, kernel_leaf_flags());
        map_leaf_page(root, ACPI_GED_BASE, ACPI_GED_BASE, kernel_leaf_flags());
        map_mmio_range(root, PCIE_ECAM_BASE, PCIE_ECAM_SIZE).expect("loongarch: map pcie ecam");
        map_mmio_range(root, PCIE_MMIO32_BASE, PCIE_MMIO32_SIZE)
            .expect("loongarch: map pcie mmio32");

        let pgd = root_frame;
        let tlbrentry = virt_to_phys(core::ptr::addr_of!(__loongarch_tlb_refill) as usize);
        let _ = boot_info;

        // PGDL/PGDH 先指向同一张根表：
        // - 内核在 DMW0 高地址窗口里继续运行；
        // - 低地址 MMIO 和后续用户页表都能复用这套 3 级 walk。
        // PWCL/PWCH 说明每一级页表的索引位置和宽度，当前都是 9 bit。
        asm!(
            "csrwr {pgdl}, 0x19",
            "csrwr {pgdh}, 0x1a",
            "csrwr {pwcl}, 0x1c",
            "csrwr {pwch}, 0x1d",
            "csrwr {stlbps}, 0x1e",
            "csrwr {tlbrentry}, 0x88",
            "csrwr {dmw0}, 0x180",
            "csrwr {dmw1}, 0x181",
            "invtlb 0x0, $zero, $zero",
            pgdl = in(reg) pgd,
            pgdh = in(reg) pgd,
            pwcl = in(reg) pwcl_3level_4k(),
            pwch = in(reg) 0usize,
            stlbps = in(reg) 12usize,
            tlbrentry = in(reg) tlbrentry,
            dmw0 = in(reg) DMW0_PLV0_CC_VSEG9,
            dmw1 = in(reg) DMW1_PLV0_SUC_VSEG8,
            options(nostack)
        );

        // CRMD.DA=0, CRMD.PG=1：关闭 direct mode，启用 mapped mode。
        // 这样 DMW0 会优先生效，而不命中的低地址则走 TLB/page table walk。
        let mut crmd: usize;
        asm!("csrrd {crmd}, 0x0", crmd = out(reg) crmd, options(nostack));
        crmd = (crmd & !(1 << 3)) | (1 << 4);
        asm!("csrwr {crmd}, 0x0", crmd = in(reg) crmd, options(nostack));
        asm!("ibar 0", "dbar 0", options(nostack));
    }
}

pub fn create_user_root() -> Result<usize, UserPagingError> {
    // 用户地址空间同样从清零页起步，避免旧 PTE 污染新进程。
    memory::alloc_zeroed_frame::<crate::LoongArch64>().ok_or(UserPagingError::OutOfMemory)
}

pub fn share_kernel_mappings(
    root_frame: usize,
    boot_info: &BootInfo,
) -> Result<(), UserPagingError> {
    let root = phys_to_virt(root_frame) as *mut PageTable;
    unsafe {
        // 用户页表也要保留内核和必要 MMIO 映射；PLV0 权限避免用户态直接访问。
        map_kernel_range(root, boot_info.kernel_start, boot_info.kernel_end)?;
        map_leaf_page(root, UART0, UART0, kernel_leaf_flags());
        map_leaf_page(root, ACPI_GED_BASE, ACPI_GED_BASE, kernel_leaf_flags());
        map_mmio_range(root, PCIE_ECAM_BASE, PCIE_ECAM_SIZE)?;
        map_mmio_range(root, PCIE_MMIO32_BASE, PCIE_MMIO32_SIZE)?;
    }
    Ok(())
}

pub fn map_user_page(root_frame: usize, mapping: UserPageMapping) -> Result<(), UserPagingError> {
    if mapping.va % 4096 != 0 || mapping.pa % 4096 != 0 {
        return Err(UserPagingError::InvalidAddress);
    }

    let root = phys_to_virt(root_frame) as *mut PageTable;
    let dir2_index = (mapping.va >> 30) & 0x1ff;
    let dir1_index = (mapping.va >> 21) & 0x1ff;
    let pte_index = (mapping.va >> 12) & 0x1ff;

    unsafe {
        // 目录项只放“下一级页表物理地址”，不能带权限位。
        let level1 = ensure_next_table(root, dir2_index)?;
        let level0 = ensure_next_table(level1, dir1_index)?;
        let pte = (align_down(mapping.pa) & PA_MASK_48) | user_leaf_flags(mapping.flags);
        core::ptr::write_volatile(core::ptr::addr_of_mut!((*level0).entries[pte_index]), pte);
    }

    Ok(())
}

pub fn enter_user(context: &luwu_kernel::UserContext) -> ! {
    unsafe extern "C" {
        fn __loongarch_enter_user(
            entry: usize,
            stack_top: usize,
            page_root: usize,
            argc: usize,
            argv: usize,
            envp: usize,
            tls: usize,
        ) -> !;
    }

    unsafe {
        __loongarch_enter_user(
            context.entry,
            context.stack_top,
            context.page_table_root,
            context.argc,
            context.argv,
            context.envp,
            context.tls,
        )
    }
}

unsafe fn ensure_next_table(
    table: *mut PageTable,
    index: usize,
) -> Result<*mut PageTable, UserPagingError> {
    let entry = unsafe { core::ptr::read_volatile(core::ptr::addr_of!((*table).entries[index])) };
    if entry != 0 {
        return Ok(phys_to_virt(entry & PA_MASK_48) as *mut PageTable);
    }

    let frame = memory::alloc_zeroed_frame::<crate::LoongArch64>().ok_or(UserPagingError::OutOfMemory)?;
    // 目录项只带 V 位，不带 PRESENT/权限位；硬件把它当作下一级页表物理地址读取。
    unsafe {
        core::ptr::write_volatile(core::ptr::addr_of_mut!((*table).entries[index]), (frame & PA_MASK_48) | PTE_V);
    }
    Ok(phys_to_virt(frame) as *mut PageTable)
}

fn kernel_leaf_flags() -> usize {
    // 内核低地址 MMIO：可写、不可执行、SUC 缓存属性，PLV0 可访问。
    PTE_V | PTE_D | PTE_MAT_SUC | PTE_G | PTE_PRESENT | PTE_WRITE | PTE_NX | PTE_PLV_KERNEL
}

fn user_leaf_flags(flags: UserMapFlags) -> usize {
    // 用户页默认可读；WRITE/EXECUTE 由抽象权限位决定。
    let mut pte = PTE_V | PTE_D | PTE_MAT_CC | PTE_PRESENT | PTE_PLV_USER;

    if flags.contains(UserMapFlags::WRITE) {
        pte |= PTE_WRITE;
    }
    if !flags.contains(UserMapFlags::READ) {
        pte |= PTE_NR;
    }
    if !flags.contains(UserMapFlags::EXECUTE) {
        pte |= PTE_NX;
    }

    pte
}

