pub fn init() {
    unsafe extern "C" {
        static __loongarch_trap_vector: u8;
    }

    // EENTRY 是普通例外入口；TLB refill 有单独的 TLBRENTRY，在 paging 初始化里设置。
    // 这里进入后只采集 ESTAT/ERA/BADV/PRMD，具体错误分类交给统一 TrapCause。
    let vector = core::ptr::addr_of!(__loongarch_trap_vector) as usize;
    unsafe {
        asm!(
            "csrwr {eentry}, 0xc",
            eentry = inout(reg) vector => _,
            options(nostack)
        );
    }
}

pub fn handle_trap<A: KernelArch + luwu_kernel::ArchUserPaging + luwu_kernel::ArchUser + 'static>(
    estate: usize,
    era: usize,
    badv: usize,
    prmd: usize,
    frame: usize,
) {
    handle_kernel_trap::<A>(TrapFrame {
        raw_cause: estate,
        epc: era,
        badv,
        status: prmd,
        saved_frame: frame,
    });
}

pub fn decode_trap_cause(estate: usize) -> TrapCause {
    let pending = estate & 0x1fff;
    let ecode = (estate >> 16) & 0x3f;
    let esubcode = (estate >> 22) & 0x1ff;

    if ecode == 0 {
        return TrapCause::Interrupt(match pending {
            0 => InterruptKind::Unknown { code: 0 },
            0x800 => InterruptKind::Timer,
            _ => InterruptKind::Platform { pending },
        });
    }

    TrapCause::Exception(match (ecode, esubcode) {
        (1, _) => ExceptionKind::LoadPageInvalid,
        (2, _) => ExceptionKind::StorePageInvalid,
        (3, _) => ExceptionKind::FetchPageInvalid,
        (4, _) => ExceptionKind::PageModify,
        (5, _) => ExceptionKind::PageNonReadable,
        (6, _) => ExceptionKind::PageNonExecutable,
        (7, _) => ExceptionKind::PagePrivilege,
        (8, _) => ExceptionKind::AddressError,
        (9, _) => ExceptionKind::AddressAlignment,
        (10, _) => ExceptionKind::BoundsCheck,
        (11, _) => ExceptionKind::Syscall,
        (12, _) => ExceptionKind::Breakpoint,
        (13, _) => ExceptionKind::IllegalInstruction,
        (14, _) => ExceptionKind::InstructionPrivilege,
        (15, _) => ExceptionKind::FloatingPointDisabled,
        (16, _) => ExceptionKind::SimdDisabled,
        (17, _) => ExceptionKind::AdvancedSimdDisabled,
        (18, _) => ExceptionKind::FloatingPointError,
        (19, _) => ExceptionKind::Watchpoint,
        (20, _) => ExceptionKind::BinaryTranslationDisabled,
        (21, _) => ExceptionKind::BinaryTranslation,
        (22, _) => ExceptionKind::GuestSensitivePrivilegedResource,
        (23, _) => ExceptionKind::HypervisorCall,
        (24, _) => ExceptionKind::GuestCsrChange,
        _ => ExceptionKind::Unknown {
            code: ecode,
            subcode: esubcode,
        },
    })
}

