#[inline]
pub fn kernel_main<A: KernelArch + init::InitConfig + ArchUserPaging + ArchUser + 'static>(boot_info: &mut BootInfo) -> ! {
    // 架构 crate 先把 entry.S 留下的原始启动信息补全成 common BootInfo。
    // 例如 RISC-V 从 FDT 找内存，LoongArch 先从 EFI config table 找 FDT。
    A::early_init(boot_info);

    console::init::<A>();
    heap::init::<A>();
    console::write_fmt::<A>(format_args!("luwu: kernel_main::<{}>() entered\n", A::NAME));

    if boot_info.is_valid() {
        console::write_fmt::<A>(format_args!(
            "boot: arg0={:#x} arg1={:#x} arg2={:#x} kernel=[{:#x}, {:#x}) stack=[{:#x}, {:#x})\n",
            boot_info.arg0,
            boot_info.arg1,
            boot_info.arg2,
            boot_info.kernel_start,
            boot_info.kernel_end,
            boot_info.boot_stack_start,
            boot_info.boot_stack_end
        ));
        console::write_fmt::<A>(format_args!(
            "boot: fdt={:#x} efi_system_table={:#x} memory_regions={}\n",
            boot_info.fdt_addr,
            boot_info.efi_system_table,
            boot_info.memory_regions().len()
        ));
        for region in boot_info.memory_regions() {
            console::write_fmt::<A>(format_args!(
                "memory: {:?} [{:#x}, {:#x})\n",
                region.kind,
                region.start,
                region.start.saturating_add(region.len)
            ));
        }

        // 从原始 BootInfo region 生成真正可分配的物理页范围。
        // 页表初始化会马上从这里拿 frame。
        match memory::init::<A>(boot_info) {
            Ok(()) => {}
            Err(error) => {
                console::write_fmt::<A>(format_args!("memory: normalize failed: {:?}\n", error));
            }
        }
    } else {
        console::write_fmt::<A>(format_args!(
            "boot: invalid BootInfo magic={:#x} version={}, continuing\n",
            boot_info.magic, boot_info.version
        ));
    }

    // 页表打开后 early console 仍必须能输出；这能同时验证 kernel 映射和 MMIO 映射。
    A::init_kernel_page_table(boot_info);
    console::write_str::<A>("luwu: paging initialized\n");
    if let Some(remaining) = memory::remaining_frames() {
        console::write_fmt::<A>(format_args!(
            "frame: after paging remaining={}\n",
            remaining
        ));
    }

    // trap 在 paging 后接入，后续 timer interrupt 会走统一 handler。
    A::init_trap();
    console::write_str::<A>("luwu: trap initialized\n");

    A::init_timer();
    console::write_str::<A>("luwu: timer initialized\n");

    async_rt::init();
    let boot_info_static = unsafe { &*(boot_info as *const BootInfo) };
    spawn_boot_tasks::<A>(boot_info_static);
    if let Some(stats) = async_rt::stats() {
        console::write_fmt::<A>(format_args!(
            "task: spawned={} ready={} sleeping={} capacity={} tick={}\n",
            stats.tasks, stats.ready, stats.sleeping, stats.capacity, stats.tick
        ));
    }
    async_rt::run::<A>()
}

fn spawn_boot_tasks<A: KernelArch + init::InitConfig + ArchUserPaging + ArchUser + 'static>(
    boot_info: &'static BootInfo,
) {
    if let Err(error) = async_rt::spawn(init::run::<A>(boot_info)) {
        console::write_fmt::<A>(format_args!("task: spawn init failed: {:?}\n", error));
    }
}

