pub async fn run<A>(boot_info: &'static BootInfo)
where
    A: KernelArch + ArchUserPaging + ArchUser + InitConfig + 'static,
{
    let tasks = A::init_tasks();
    let root = match fs::mount_root::<A>() {
        Ok(root) => root,
        Err(error) => {
            console::write_fmt::<A>(format_args!("init: mount failed: {:?}\n", error));
            if !tasks.is_empty() {
                console::write_str::<A>("init: configured user tasks require rootfs, poweroff\n");
                A::poweroff();
            }
            shell::run::<A>().await;
        }
    };

    let root = Box::leak(Box::new(root));
    process::set_current_root::<A>(root);
    process::reset_fds();

    if tasks.is_empty() {
        console::write_str::<A>("init: no configured user tasks\n");
        shell::run::<A>().await;
    }

    for task in tasks {
        match prepare_task::<A>(boot_info, root, task).await {
            Ok(prepared) => {
                let prepared = Box::leak(Box::new(prepared));
                console::write_fmt::<A>(format_args!(
                    "init: image {} machine={:#x} segments={}\n",
                    task.name,
                    prepared.task.image.machine,
                    prepared.task.image.segments.len()
                ));
                for segment in &prepared.task.image.segments {
                    console::write_fmt::<A>(format_args!(
                        "init: segment va={:#x} mem={:#x} file={:#x} flags={:#x}\n",
                        segment.virtual_addr, segment.memory_size, segment.file_size, segment.flags
                    ));
                }
                console::write_str::<A>("init: prepared user task\n");
                if task.enter_user {
                    process::init(boot_info, &prepared.memory);
                    syscall::set_program_break(prepared.task.image.brk_start());
                    trap::set_kernel_resume_epc(init_user_resume::<A> as *const () as usize);
                    console::write_str::<A>("init: entering user\n");
                    A::enter_user(&prepared.context);
                    console::write_str::<A>("init: enter_user returned\n");
                }
            }
            Err(error) => {
                console::write_fmt::<A>(format_args!(
                    "init: prepare {} failed: {:?}\n",
                    task.name, error
                ));
                if task.argv.last().copied() == Some(OSCOMP_SCAN_ROOT_SENTINEL) {
                    console::write_str::<A>("init: oscomp task cannot continue, poweroff\n");
                    A::poweroff();
                }
            }
