async fn prepare_task<A>(
    boot_info: &BootInfo,
    root: &fs::RootFs<A>,
    task: &InitTask,
) -> Result<PreparedInitTask, InitError>
where
    A: KernelArch + ArchUserPaging,
{
    let user_task = user::prepare_from_path::<A>(root, task.path)
        .await
        .map_err(InitError::User)?;
    let argv = resolve_task_argv::<A>(root, task)?;
    let space = user_task
        .image
        .prepare_address_space()
        .map_err(InitError::User)?;
    let memory =
        user_paging::UserMemory::create::<A>(boot_info, &space).map_err(InitError::Paging)?;
    user_paging::load_elf_segments::<A>(root, task.path, &memory, &user_task.image)
        .await
        .map_err(InitError::Load)?;
    let stack = memory
        .prepare_user_stack(&user_task.image, space.stack_range().end, argv, task.envp)
        .map_err(InitError::Paging)?;
    let tls = memory.allocate_tls::<A>().unwrap_or(0);
    if let Err(e) = memory.load_tls_template::<A>(root, task.path, &user_task.image) {
        console::write_fmt::<A>(format_args!("init: tls load failed: {:?}\n", e));
    }
    let context = memory.user_context(user_task.image.entry as usize, stack, tls);

    Ok(PreparedInitTask {
        task: user_task,
        memory,
        context,
    })
}

