pub fn normalize_path(path: &str) -> Option<String> {
    if path.is_empty() {
        return None;
    }
    let mut normalized = if path.starts_with('/') {
        String::new()
    } else {
        current_cwd()?
    };
    if !normalized.ends_with('/') {
        normalized.push('/');
    }
    normalized.push_str(path);

    let mut parts: Vec<&str> = Vec::new();
    for part in normalized.split('/') {
        match part {
            "" | "." => {}
            ".." => {
                parts.pop();
            }
            value => parts.push(value),
        }
    }
    let mut result = String::from("/");
    result.push_str(&parts.join("/"));
    if result.len() > 1 && result.ends_with('/') {
        result.pop();
    }
    Some(alias_path(result))
}

fn alias_path(path: String) -> String {
    let libc_kind = LIBC_KIND.load(Ordering::SeqCst);
    let lib_prefix: &str = if libc_kind == 2 { "/musl/lib/" } else { "/glibc/lib/" };

    // musl 动态链接器：/lib/ld-musl-*.so.1 → /musl/lib/libc.so
    // musl 的 libc.so 同时充当 ld.so
    if libc_kind == 2 && path.starts_with("/lib/ld-musl") {
        return String::from("/musl/lib/libc.so");
    }

    if let Some(suffix) = path.strip_prefix("/lib64/") {
        let mut mapped = String::from(lib_prefix);
        mapped.push_str(suffix);
        mapped
    } else if let Some(suffix) = path.strip_prefix("/usr/lib64/") {
        let mut mapped = String::from(lib_prefix);
        mapped.push_str(suffix);
        mapped
    } else if let Some(suffix) = path.strip_prefix("/lib/") {
        let mut mapped = String::from(lib_prefix);
        mapped.push_str(suffix);
        mapped
    } else {
        path
    }
}

