pub(super) fn sys_execve<A: KernelArch + crate::ArchUserPaging + ArchUser + 'static>(
    path_ptr: usize,
    argv_ptr: usize,
    envp_ptr: usize,
) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let Some((raw_path, normalized_path)) = process::resolve_exec_path(memory, path_ptr) else {
        return SyscallOutcome::Return(ENOENT);
    };
    let mut path = normalized_path;
    let Some(mut argv) = read_string_array(memory, argv_ptr, 32) else {
        return SyscallOutcome::Return(ENOENT);
    };
    let Some(envp) = read_string_array(memory, envp_ptr, 64) else {
        return SyscallOutcome::Return(ENOENT);
    };
    if path.starts_with("/bin/") {
        let applet = String::from(path.rsplit('/').next().unwrap_or(""));
        path = String::from("/glibc/busybox");
        argv.insert(0, String::from("/glibc/busybox"));
        if argv.get(1).map(String::as_str) != Some(applet.as_str()) {
            argv.insert(1, applet);
        }
    }

    match process::exec_current::<A>(&path, &argv, &envp) {
        Ok(image) => {
            set_program_break(image.brk_start);
            A::enter_user(&image.context);
            unreachable!("execve returned from user entry")
        }
        Err(error) => {
            if matches!(
                error,
                process::ExecError::User(user::UserError::Elf(crate::elf::ElfError::BadMagic))
            ) {
                let script_path = raw_path;
                path = String::from("/glibc/busybox");
                argv.clear();
                argv.push(String::from("/glibc/busybox"));
                argv.push(String::from("sh"));
                argv.push(script_path);
                match process::exec_current::<A>(&path, &argv, &envp) {
                    Ok(image) => {
                        set_program_break(image.brk_start);
                        A::enter_user(&image.context);
                        unreachable!("script execve returned from user entry")
                    }
                    Err(error) => {
                        console::write_fmt::<A>(format_args!(
                            "process: script execve failed: {:?}\n",
                            error
                        ));
                        return SyscallOutcome::Return(ENOENT);
                    }
                }
            }
            console::write_fmt::<A>(format_args!(
                "process: execve {} failed: {:?}\n",
                path, error
            ));
            SyscallOutcome::Return(ENOENT)
        }
    }
}

pub(super) fn sys_syslog<A: KernelArch>(kind: usize, buf: usize, len: usize) -> SyscallOutcome {
    const LOG: &[u8] = b"luwu: kernel log buffer\n";
    match kind {
        10 => SyscallOutcome::Return(LOG.len() as isize),
        3 | 4 => {
            let Some(memory) = process::current_user_memory() else {
                return SyscallOutcome::Return(ENOSYS);
            };
            let count = core::cmp::min(len, LOG.len());
            if count != 0 && memory.write_user_bytes(buf, &LOG[..count]).is_err() {
                return SyscallOutcome::Return(ENOSYS);
            }
            SyscallOutcome::Return(count as isize)
        }
        _ => SyscallOutcome::Return(0),
    }
}

pub(super) fn read_string_array(
    memory: &crate::user_paging::UserMemory,
    mut ptr: usize,
    max_items: usize,
) -> Option<Vec<String>> {
    let mut values = Vec::new();
    for _ in 0..max_items {
        let raw = memory
            .read_user_bytes(ptr, core::mem::size_of::<usize>())
            .ok()?;
        let value = usize::from_le_bytes(raw[..core::mem::size_of::<usize>()].try_into().ok()?);
        if value == 0 {
            return Some(values);
        }
        let bytes = memory.read_user_cstr(value).ok()?;
        values.push(String::from_utf8(bytes).ok()?);
        ptr += core::mem::size_of::<usize>();
    }
    None
}

pub(super) fn sys_clone<A: KernelArch + crate::ArchUserPaging>(
    frame: &crate::TrapFrame,
    flags: usize,
    child_stack: usize,
    tls: usize,
) -> SyscallOutcome {
    match process::fork_current::<A>(frame, flags, child_stack, tls) {
        Ok(pid) => SyscallOutcome::Return(pid as isize),
        Err(process::ForkError::UnsupportedFlags) => SyscallOutcome::Return(EAGAIN),
        Err(error) => {
            console::write_fmt::<A>(format_args!("process: clone failed: {:?}\n", error));
            SyscallOutcome::Return(ENOSYS)
        }
    }
}

pub(super) fn sys_kill<A: KernelArch>(pid: usize) -> SyscallOutcome {
    if pid != 0 {
        let _ = process::kill_process(pid, 128 + 15);
    }
    SyscallOutcome::Return(0)
}

pub(super) fn sys_wait4<A: KernelArch>(
    frame: &crate::TrapFrame,
    pid: usize,
    status_ptr: usize,
) -> SyscallOutcome {
    let parent_pid = process::current_pid();
    let requested_pid = if pid == usize::MAX || pid == 0 {
        usize::MAX
    } else {
        pid
    };
    if let Some((child_pid, code)) = process::take_waitable_child(parent_pid, requested_pid) {
        if status_ptr != 0 {
            if let Some(memory) = process::current_user_memory() {
                let _ = memory.write_user_u32(status_ptr, (code << 8) as u32);
            }
        }
        return SyscallOutcome::Return(child_pid as isize);
    }

    let Some(child) = process::take_runnable_child(parent_pid, requested_pid) else {
        return SyscallOutcome::Return(-10);
    };
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let parent_context = A::capture_user_context(frame, memory.root);
    if !process::set_waiting(parent_pid, requested_pid, status_ptr, parent_context) {
        return SyscallOutcome::Return(ENOSYS);
    }
    process::switch_to_process::<A>(child)
}

