const AT_FDCWD: usize = usize::MAX - 99;

pub(super) fn resolve_user_path_at(
    memory: &crate::user_paging::UserMemory,
    dirfd: usize,
    path_ptr: usize,
) -> Option<String> {
    let raw = process::path_from_user(memory, path_ptr)?;
    if raw.starts_with('/') || dirfd == AT_FDCWD {
        return process::normalize_path(&raw);
    }
    let base = match process::get_fd(dirfd)? {
        process::FileDescriptor::Memory { id, .. } => memory_file_path(id)?,
        process::FileDescriptor::Directory => process::current_cwd()?,
        _ => return None,
    };
    let joined = if base == "/" {
        alloc::format!("/{}", raw)
    } else if raw.is_empty() {
        base
    } else {
        alloc::format!("{}/{}", base, raw)
    };
    process::normalize_path(&joined)
}

pub(super) fn memory_file_id(path: &str) -> Option<usize> {
    unsafe {
        let files = &*MEMORY_FILES.inner.get();
        files.iter().position(|file| file.path == path)
    }
}

pub(super) fn memory_file_path(id: usize) -> Option<String> {
    unsafe {
        let files = &*MEMORY_FILES.inner.get();
        files.get(id).map(|file| file.path.clone())
    }
}

pub(super) fn memory_file_len(id: usize) -> Option<usize> {
    unsafe {
        let files = &*MEMORY_FILES.inner.get();
        files.get(id).map(|file| file.data.len())
    }
}

pub(super) fn memory_file_bytes(id: usize) -> Option<Vec<u8>> {
    unsafe {
        let files = &*MEMORY_FILES.inner.get();
        files.get(id).map(|file| file.data.clone())
    }
}

pub(super) fn rename_memory_path(old_path: &str, new_path: &str) {
    unsafe {
        let files = &mut *MEMORY_FILES.inner.get();
        if let Some(file) = files.iter_mut().find(|file| file.path == old_path) {
            file.path = String::from(new_path);
        }
        let dirs = &mut *MEMORY_DIRS.inner.get();
        if let Some(dir) = dirs.iter_mut().find(|dir| dir.as_str() == old_path) {
            *dir = String::from(new_path);
        }
    }
}

pub(super) fn create_memory_file(path: &str) -> usize {
    create_memory_file_with(path, &[])
}

pub(super) fn create_memory_file_with(path: &str, data: &[u8]) -> usize {
    unsafe {
        let files = &mut *MEMORY_FILES.inner.get();
        if let Some(index) = files.iter().position(|file| file.path == path) {
            files[index].data.clear();
            files[index].data.extend_from_slice(data);
            return index;
        }
        files.push(MemoryFile {
            path: String::from(path),
            data: data.to_vec(),
            is_pipe: false,
            pipe_writers: 0,
        });
        files.len() - 1
    }
}

pub(super) fn create_memory_pipe(path: &str) -> usize {
    unsafe {
        let files = &mut *MEMORY_FILES.inner.get();
        files.push(MemoryFile {
            path: String::from(path),
            data: Vec::new(),
            is_pipe: true,
            pipe_writers: 1,
        });
        files.len() - 1
    }
}

pub(crate) fn close_pipe_write_end(id: usize) {
    unsafe {
        let files = &mut *MEMORY_FILES.inner.get();
        if let Some(file) = files.get_mut(id) {
            if file.is_pipe && file.pipe_writers > 0 {
                file.pipe_writers -= 1;
            }
        }
    }
}

pub(super) fn write_memory_file(
    memory: &crate::user_paging::UserMemory,
    id: usize,
    offset: &mut u64,
    user_buf: usize,
    len: usize,
) -> Result<(), ()> {
    let bytes = memory.read_user_bytes(user_buf, len).map_err(|_| ())?;
    write_memory_file_bytes(id, offset, &bytes)
}

pub(super) fn write_memory_file_bytes(id: usize, offset: &mut u64, bytes: &[u8]) -> Result<(), ()> {
    unsafe {
        let files = &mut *MEMORY_FILES.inner.get();
        let file = files.get_mut(id).ok_or(())?;
        let start = *offset as usize;
        let end = start.checked_add(bytes.len()).ok_or(())?;
        if file.data.len() < end {
            file.data.resize(end, 0);
        }
        file.data[start..end].copy_from_slice(bytes);
        *offset = end as u64;
    }
    Ok(())
}

