    fd: usize,
    user_buf: usize,
    len: usize,
    offset: usize,
) -> SyscallOutcome {
    sys_pread_like::<A>(fd, user_buf, len, Some(offset as u64))
}

pub(super) fn sys_pread_like<A: KernelArch + 'static>(
    fd: usize,
    user_buf: usize,
    len: usize,
    offset: Option<u64>,
) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    if fd < 3 {
        return SyscallOutcome::Return(0);
    }

    let mut scratch = alloc::vec![0u8; len];
    let read = match read_fd_kernel::<A>(fd, &mut scratch, offset) {
        Ok(read) => read,
        Err(value) => return SyscallOutcome::Return(value),
    };
    if memory.write_user_bytes(user_buf, &scratch[..read]).is_err() {
        return SyscallOutcome::Return(ENOSYS);
    }
    SyscallOutcome::Return(read as isize)
}

