            let read_offset = offset.unwrap_or(*file_offset) as usize;
            let result = read_memory_file_with_pipe_wait(*id, read_offset, scratch);
            if offset.is_none() {
                if let Ok(read) = result {
                    *file_offset += read as u64;
                }
            }
            result.map_err(|_| ENOENT)
        },
        process::FileDescriptor::Stdio { .. } | process::FileDescriptor::Directory => Ok(0),
    }) else {
        return Err(EBADF);
    };
    read
}

/// 从 Memory 文件读取，对 pipe 类型做空等重试
unsafe fn read_memory_file_with_pipe_wait(
    id: usize,
    read_offset: usize,
    scratch: &mut [u8],
) -> Result<usize, ()> {
    unsafe {
        let files = &*MEMORY_FILES.inner.get();
        let Some(file) = files.get(id) else {
            return Err(());
        };
        // 普通文件：直接读
        if !file.is_pipe {
            if read_offset >= file.data.len() {
                return Ok(0);
            }
            let read = core::cmp::min(scratch.len(), file.data.len() - read_offset);
            scratch[..read].copy_from_slice(&file.data[read_offset..read_offset + read]);
            return Ok(read);
        }
        // 管道：空时短暂等写端写入（最多等 100000 次迭代）
        for _ in 0..100000 {
            let files = &*MEMORY_FILES.inner.get();
            let Some(file) = files.get(id) else {
                return Err(());
            };
            if read_offset < file.data.len() {
                let read = core::cmp::min(scratch.len(), file.data.len() - read_offset);
                scratch[..read].copy_from_slice(&file.data[read_offset..read_offset + read]);
                return Ok(read);
            }
            core::hint::spin_loop();
        }
        // 超时：返回 0 (EOF)
        Ok(0)
    }
}

pub(super) fn sys_getdents64<A: KernelArch + 'static>(
    fd: usize,
    user_buf: usize,
    len: usize,
) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    if len == 0 {
        return SyscallOutcome::Return(0);
    }
    let Some(result) = process::with_fd_mut(fd, |file| match file {
        process::FileDescriptor::Memory {
            id,
            offset: file_offset,
        } => unsafe {
            let files = &*MEMORY_FILES.inner.get();
            let Some(file) = files.get(*id) else {
                return Err(ENOENT);
            };
            let start = *file_offset as usize;
            if start >= file.data.len() {
                return Ok(0usize);
            }
            let mut end = start;
            while end < file.data.len() {
                if end + 19 > file.data.len() {
                    break;
                }
                let reclen = u16::from_le_bytes([file.data[end + 16], file.data[end + 17]]) as usize;
                if reclen == 0 || end + reclen > file.data.len() || end + reclen - start > len {
                    break;
                }
                end += reclen;
            }
            if end == start {
                return Err(EMFILE);
            }
            let bytes = &file.data[start..end];
            memory.write_user_bytes(user_buf, bytes).map_err(|_| ENOSYS)?;
            *file_offset = end as u64;
            Ok(bytes.len())
        },
        _ => Err(EBADF),
    }) else {
        return SyscallOutcome::Return(EBADF);
    };
    match result {
        Ok(read) => SyscallOutcome::Return(read as isize),
        Err(error) => SyscallOutcome::Return(error),
    }
}

pub(super) fn sys_readv<A: KernelArch + 'static>(fd: usize, iov: usize, iovcnt: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let mut total = 0usize;
    for index in 0..iovcnt {
        let descriptor = iov + index * 16;
        let Ok(base_bytes) = memory.read_user_bytes(descriptor, 8) else {
            return SyscallOutcome::Return(ENOSYS);
        };
        let Ok(len_bytes) = memory.read_user_bytes(descriptor + 8, 8) else {
            return SyscallOutcome::Return(ENOSYS);
        };
        let base = usize::from_le_bytes(base_bytes[..8].try_into().unwrap_or([0; 8]));
        let len = usize::from_le_bytes(len_bytes[..8].try_into().unwrap_or([0; 8]));
        match sys_read::<A>(fd, base, len) {
            SyscallOutcome::Return(value) if value > 0 => total += value as usize,
            SyscallOutcome::Return(0) => break,
            outcome => return outcome,
        }
    }
    SyscallOutcome::Return(total as isize)
}

