pub(super) fn sys_sendfile<A: KernelArch + 'static>(
    out_fd: usize,
    in_fd: usize,
    offset_ptr: usize,
    count: usize,
) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let offset = if offset_ptr == 0 {
        None
    } else {
        let Ok(bytes) = memory.read_user_bytes(offset_ptr, 8) else {
            return SyscallOutcome::Return(ENOSYS);
        };
        Some(u64::from_le_bytes(bytes[..8].try_into().unwrap_or([0; 8])))
    };
    let mut scratch = alloc::vec![0u8; core::cmp::min(count, 4096)];
    let read = match read_fd_kernel::<A>(in_fd, &mut scratch, offset) {
        Ok(read) => read,
        Err(value) => return SyscallOutcome::Return(value),
    };
    if read == 0 {
        return SyscallOutcome::Return(0);
    }
    if offset_ptr != 0 {
        let next = offset.unwrap_or(0) + read as u64;
        let _ = memory.write_user_bytes(offset_ptr, &next.to_le_bytes());
    }
    let write_result = if out_fd == FD_STDOUT || out_fd == FD_STDERR {
        for byte in &scratch[..read] {
            console::write_byte::<A>(*byte);
        }
        Ok(())
    } else {
        process::with_fd_mut(out_fd, |file| match file {
            process::FileDescriptor::Memory { id, offset } => {
                write_memory_file_bytes(*id, offset, &scratch[..read])
            }
            process::FileDescriptor::Stdio { fd } if *fd == FD_STDOUT || *fd == FD_STDERR => Ok(()),
            process::FileDescriptor::Ext4 { ino, offset } => {
                let Some(root) = process::current_root_mut::<A>() else {
                    return Err(());
                };
                let wrote = root.write(*ino, *offset, &scratch[..read]).map_err(|_| ())?;
                *offset += wrote as u64;
                Ok(())
            }
            process::FileDescriptor::Directory | process::FileDescriptor::Stdio { .. } => Err(()),
        })
        .unwrap_or(Err(()))
    };
    match write_result {
        Ok(()) => SyscallOutcome::Return(read as isize),
        Err(()) => SyscallOutcome::Return(EBADF),
    }
}

pub(super) fn sys_write<A: KernelArch + 'static>(fd: usize, user_buf: usize, len: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };

    // 解析最终目标 fd：可能是直接 stdout/stderr，也可能是 dup2 重定向后的
    let console_fd = if fd == FD_STDOUT || fd == FD_STDERR {
        Some(fd)
    } else {
        match process::get_fd(fd) {
            Some(process::FileDescriptor::Stdio { fd: target })
                if target == FD_STDOUT || target == FD_STDERR =>
            {
                Some(target)
            }
            _ => None,
        }
    };

    if console_fd.is_some() {
        // 写到串口控制台
        const CHUNK: usize = 128;
        let mut copied = 0usize;
        while copied < len {
            let chunk_len = core::cmp::min(CHUNK, len - copied);
            match memory.read_user_bytes(user_buf + copied, chunk_len) {
                Ok(bytes) => {
                    for byte in bytes {
                        console::write_byte::<A>(byte);
                    }
                }
                Err(_) => return SyscallOutcome::Return(ENOSYS),
            }
            copied += chunk_len;
        }
        return SyscallOutcome::Return(len as isize);
    }

    let Some(result) = process::with_fd_mut(fd, |file| match file {
        process::FileDescriptor::Memory { id, offset } => {
            write_memory_file(memory, *id, offset, user_buf, len)
        }
        process::FileDescriptor::Ext4 { ino, offset } => {
            let bytes = memory.read_user_bytes(user_buf, len).map_err(|_| ())?;
            let Some(root) = process::current_root_mut::<A>() else {
                return Err(());
            };
            let wrote = root.write(*ino, *offset, &bytes).map_err(|_| ())?;
            *offset += wrote as u64;
            Ok(())
        }
        process::FileDescriptor::Stdio { .. } | process::FileDescriptor::Directory => Err(()),
    }) else {
        return SyscallOutcome::Return(EBADF);
    };
    match result {
        Ok(()) => SyscallOutcome::Return(len as isize),
        Err(()) => SyscallOutcome::Return(EBADF),
    }
}

