pub(super) fn sys_mkdirat<A: KernelArch + 'static>(dirfd: usize, path_ptr: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let Some(path) = resolve_user_path_at(memory, dirfd, path_ptr) else {
        return SyscallOutcome::Return(ENOENT);
    };
    if path == "/" || directory_exists::<A>(&path) {
        return SyscallOutcome::Return(0);
    }
    if let Some(root) = process::current_root_mut::<A>() {
        if let Ok((parent, name)) = root.resolve_parent(&path) {
            if root.mkdir(parent, &name, 0o755, 0, 0).is_ok() {
                return SyscallOutcome::Return(0);
            }
        }
    }
    remember_directory(&path);
    SyscallOutcome::Return(0)
}

pub(super) fn sys_getcwd(user_buf: usize, len: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let Some(cwd) = process::current_cwd() else {
        return SyscallOutcome::Return(ENOENT);
    };
    if len < cwd.len() + 1 {
        return SyscallOutcome::Return(ENOSPC);
    }
    if memory.write_user_bytes(user_buf, cwd.as_bytes()).is_err()
        || memory.write_user_bytes(user_buf + cwd.len(), &[0]).is_err()
    {
        return SyscallOutcome::Return(ENOSYS);
    }
    SyscallOutcome::Return(user_buf as isize)
}

pub(super) fn sys_chdir<A: KernelArch + 'static>(path_ptr: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let Some(path) = process::resolve_user_path(memory, path_ptr) else {
        return SyscallOutcome::Return(ENOENT);
    };

    if !directory_exists::<A>(&path) {
        return SyscallOutcome::Return(ENOENT);
    }
    if process::set_current_cwd(path) {
        SyscallOutcome::Return(0)
    } else {
        SyscallOutcome::Return(ENOSYS)
    }
}

pub(super) fn remember_directory(path: &str) {
    unsafe {
        let dirs = &mut *MEMORY_DIRS.inner.get();
        if dirs.iter().all(|dir| dir != path) {
            dirs.push(String::from(path));
        }
    }
}

pub(super) fn sys_unlinkat<A: KernelArch + 'static>(dirfd: usize, path_ptr: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let Some(path) = resolve_user_path_at(memory, dirfd, path_ptr) else {
        return SyscallOutcome::Return(ENOENT);
    };
    if let Some(root) = process::current_root_mut::<A>() {
        if let Ok((parent, name)) = root.resolve_parent(&path) {
            let _ = root.unlink(parent, &name).or_else(|_| root.rmdir(parent, &name));
        }
    }
    unsafe {
        let files = &mut *MEMORY_FILES.inner.get();
        if let Some(index) = files.iter().position(|file| file.path == path) {
            files.remove(index);
        }
    }
    SyscallOutcome::Return(0)
}

