pub(super) fn itoa(mut value: usize) -> String {
    if value == 0 {
        return String::from("0");
    }
    let mut digits = [0u8; 20];
    let mut len = 0usize;
    while value != 0 {
        digits[len] = b'0' + (value % 10) as u8;
        value /= 10;
        len += 1;
    }
    let mut out = String::new();
    while len != 0 {
        len -= 1;
        out.push(digits[len] as char);
    }
    out
}

pub(super) fn sys_close(fd: usize) -> SyscallOutcome {
    // 在关闭前检查是否为管道写端，递减写端计数
    if let Some(process::FileDescriptor::Memory { id, .. }) = process::get_fd(fd) {
        close_pipe_write_end(id);
    }
    if fd < 3 || process::close_fd(fd) {
        SyscallOutcome::Return(0)
    } else {
        SyscallOutcome::Return(EBADF)
    }
}

pub(super) fn sys_lseek(fd: usize, offset: usize, whence: usize) -> SyscallOutcome {
    // SEEK_END 需要知道文件大小
    let file_size: Option<u64> = if whence == 2 {
        match process::get_fd(fd) {
            Some(process::FileDescriptor::Memory { id, .. }) => {
                memory_file_len(id).map(|len| len as u64)
            }
            _ => None,
        }
    } else {
        None
    };

    let Some(result) = process::with_fd_mut(fd, |file| {
        let next = match whence {
            0 => offset as i64,
            1 => match file {
                process::FileDescriptor::Ext4 {
                    offset: file_offset,
                    ..
                }
                | process::FileDescriptor::Memory {
                    offset: file_offset,
                    ..
                } => *file_offset as i64 + offset as i64,
                process::FileDescriptor::Stdio { .. } | process::FileDescriptor::Directory => {
                    return None;
                }
            },
            2 => {
                let Some(size) = file_size else {
                    return None;
                };
                size as i64 + offset as i64
            }
            _ => return None,
        };
        if next < 0 {
            return None;
        }
        match file {
            process::FileDescriptor::Ext4 {
                offset: file_offset,
                ..
            }
            | process::FileDescriptor::Memory {
                offset: file_offset,
                ..
            } => {
                *file_offset = next as u64;
                Some(*file_offset as isize)
            }
            process::FileDescriptor::Stdio { .. } | process::FileDescriptor::Directory => None,
        }
    }) else {
        return SyscallOutcome::Return(EBADF);
    };
    match result {
        Some(value) => SyscallOutcome::Return(value),
        None => SyscallOutcome::Return(-22),
    }
}

use core::cell::UnsafeCell;

pub use luwu_common::memory::{
    FrameAllocator, MEMORY_RANGES_MAX, MemoryMap, MemoryMapError, PhysRange,
};
use luwu_common::{BootInfo, paging::PAGE_SIZE};

use crate::{KernelArch, console};

struct GlobalFrameAllocator {
    inner: UnsafeCell<Option<FrameAllocator>>,
}

// 当前内核还没有多核启动，也没有抢占式调度。这个全局 allocator 只在早期
// 单核路径里被访问，所以先用 UnsafeCell 包起来，后面接 SMP 时要换成带锁版本。
unsafe impl Sync for GlobalFrameAllocator {}

static FRAME_ALLOCATOR: GlobalFrameAllocator = GlobalFrameAllocator {
    inner: UnsafeCell::new(None),
};

pub fn init<A: KernelArch>(boot_info: &BootInfo) -> Result<(), MemoryMapError> {
    // common 层负责把 BootInfo 的原始 region 归一化；kernel 层只关心结果能不能分配。
    let map = MemoryMap::from_boot_info(boot_info)?;

    console::write_fmt::<A>(format_args!(
        "memory: normalized usable={} total={} KiB\n",
        map.usable_ranges().len(),
        map.total_usable_bytes() / 1024
    ));
    for range in map.usable_ranges() {
        console::write_fmt::<A>(format_args!(
            "memory: allocatable [{:#x}, {:#x})\n",
            range.start, range.end
        ));
    }

    let allocator = FrameAllocator::new(&map);
    console::write_fmt::<A>(format_args!(
        "frame: available={}\n",
        allocator.remaining_frames()
    ));

    unsafe {
        // MemoryMap 是临时构建物，FrameAllocator 已经拷贝了可分配范围，
        // 所以这里保存 allocator 本体即可。
        *FRAME_ALLOCATOR.inner.get() = Some(allocator);
    }
    Ok(())
}

pub fn alloc_frame() -> Option<usize> {
    // 早期失败直接交给调用者 panic/report。这里不隐藏 OOM，方便看出页表建在哪里失败。
    unsafe { (*FRAME_ALLOCATOR.inner.get()).as_mut()?.alloc_frame() }
}

pub fn alloc_zeroed_frame<A: KernelArch>() -> Option<usize> {
    let frame = alloc_frame()?;
    unsafe {
        // 页表页必须先清零，否则旧内存里的随机 bit 会被硬件解释成有效 PTE。
        // 回收页再次分配时也必须清零，避免用户地址空间泄漏旧内容。
        let ptr = A::phys_to_virt(frame) as *mut usize;
        for index in 0..(PAGE_SIZE / core::mem::size_of::<usize>()) {
            core::ptr::write_volatile(ptr.add(index), 0);
        }
    }
    Some(frame)
}

pub fn free_frame(frame: usize) -> bool {
    unsafe { (*FRAME_ALLOCATOR.inner.get()).as_mut().is_some_and(|allocator| allocator.free_frame(frame)) }
}

pub fn remaining_frames() -> Option<usize> {
    unsafe {
        (*FRAME_ALLOCATOR.inner.get())
            .as_ref()
            .map(FrameAllocator::remaining_frames)
    }
}

