                let pa = memory::alloc_zeroed_frame::<A>().ok_or(UserPagingError::OutOfMemory)?;
                A::map_user_page(
                    root,
                    UserPageMapping {
                        va,
                        pa,
                        flags: mapping.perm.to_user_flags(),
                    },
                )?;
                pages.push(UserPage {
                    va,
                    pa,
                    flags: mapping.perm.to_user_flags(),
                });
                va += PAGE_SIZE;
            }
        }

        Ok(Self {
            root,
            pages: UnsafeCell::new(pages),
            phys_to_virt: A::phys_to_virt,
        })
    }

    pub fn clone_for_fork<A: KernelArch + ArchUserPaging>(
        &self,
