        let root = A::create_user_root()?;
        A::share_kernel_mappings(root, boot_info)?;
        let mut pages = Vec::new();

        for page in unsafe { &*self.pages.get() } {
            let pa = memory::alloc_zeroed_frame::<A>().ok_or(UserPagingError::OutOfMemory)?;
            A::map_user_page(
                root,
                UserPageMapping {
                    va: page.va,
                    pa,
                    flags: page.flags,
                },
            )?;
            unsafe {
                core::ptr::copy_nonoverlapping(
