                    A::phys_to_virt(pa) as *mut u8,
                    PAGE_SIZE,
                );
            }
            pages.push(UserPage {
                va: page.va,
                pa,
                flags: page.flags,
            });
        }

        Ok(Self {
            root,
            pages: UnsafeCell::new(pages),
            phys_to_virt: A::phys_to_virt,
        })
    }

    pub fn map_anonymous_range<A: KernelArch + ArchUserPaging>(
        &self,
        start: usize,
        len: usize,
        flags: UserMapFlags,
    ) -> Result<(), UserPagingError> {
        let mut va = align_down(start);
        let end = luwu_common::paging::align_up(start.saturating_add(len));
        while va < end {
            if let Some(pa) = self.phys_for_va(va) {
                // 页面已存在：更新 PTE 权限（支持 MAP_FIXED 重映射）
                A::map_user_page(self.root, UserPageMapping { va, pa, flags })?;
                unsafe {
                    let pages = &mut *self.pages.get();
                    if let Some(page) = pages.iter_mut().find(|p| p.va == va) {
                        page.flags = flags;
                    }
                }
            } else {
                let pa = memory::alloc_zeroed_frame::<A>().ok_or(UserPagingError::OutOfMemory)?;
                A::map_user_page(self.root, UserPageMapping { va, pa, flags })?;
                unsafe { &mut *self.pages.get() }.push(UserPage { va, pa, flags });
            }
            va += PAGE_SIZE;
        }
        Ok(())
    }

    pub fn unmap_range(&self, start: usize, len: usize) {
        let page_start = luwu_common::paging::align_down(start);
        let page_end = luwu_common::paging::align_up(start.saturating_add(len));
        let pages = unsafe { &mut *self.pages.get() };
        pages.retain(|page| {
            if page.va >= page_start && page.va < page_end {
                let _ = memory::free_frame(page.pa);
                false
            } else {
                true
            }
        });
    }

