use alloc::vec::Vec;

use crate::{KernelArch, fs};

const EI_CLASS: usize = 4;
const EI_DATA: usize = 5;
const ELFCLASS64: u8 = 2;
const ELFDATA2LSB: u8 = 1;
const PT_LOAD: u32 = 1;
const PT_INTERP: u32 = 3;
const PT_TLS: u32 = 7;

pub async fn inspect<A: KernelArch>(root: &fs::RootFs<A>, path: &str) -> Result<ElfImage, ElfError> {
    inspect_sync(root, path)
}

pub fn inspect_sync<A: KernelArch>(root: &fs::RootFs<A>, path: &str) -> Result<ElfImage, ElfError> {
    let mut ident = [0u8; 64];
    let read = fs::read_file(root, path, 0, &mut ident).map_err(ElfError::Fs)?;
    if read < ident.len() {
        return Err(ElfError::Truncated);
    }

    let header = ElfHeader::parse(&ident)?;
    let ph_bytes_len = header
        .program_header_entry_size
        .checked_mul(header.program_header_count as usize)
        .ok_or(ElfError::InvalidHeader)?;
    let mut ph_bytes = Vec::new();
    ph_bytes.resize(ph_bytes_len, 0);
    let read = fs::read_file(root, path, header.program_header_offset, &mut ph_bytes)
        .map_err(ElfError::Fs)?;
    if read < ph_bytes.len() {
        return Err(ElfError::Truncated);
    }

    let mut load_segments = Vec::new();
    let mut interpreter = None;
    let mut tls = None;
    for index in 0..header.program_header_count as usize {
        let start = index * header.program_header_entry_size;
        let end = start + header.program_header_entry_size;
        let ph = ProgramHeader::parse(&ph_bytes[start..end])?;
        if ph.ty == PT_LOAD {
            load_segments.push(LoadSegment {
                file_offset: ph.offset,
                virtual_addr: ph.vaddr,
                file_size: ph.file_size,
                memory_size: ph.memory_size,
                flags: ph.flags,
                align: ph.align,
            });
        } else if ph.ty == PT_INTERP {
            let mut bytes = Vec::new();
            bytes.resize(ph.file_size as usize, 0);
            let read = fs::read_file(root, path, ph.offset, &mut bytes).map_err(ElfError::Fs)?;
            if read < bytes.len() {
                return Err(ElfError::Truncated);
            }
            if let Some(end) = bytes.iter().position(|byte| *byte == 0) {
                bytes.truncate(end);
            }
            interpreter = Some(alloc::string::String::from_utf8(bytes).map_err(|_| ElfError::InvalidHeader)?);
        } else if ph.ty == PT_TLS {
            tls = Some(TlsInfo {
                file_offset: ph.offset,
                virtual_addr: ph.vaddr,
                file_size: ph.file_size,
                memory_size: ph.memory_size,
            });
        }
    }

    Ok(ElfImage {
        ty: header.ty,
        entry: header.entry,
        machine: header.machine,
        program_header_offset: header.program_header_offset,
        program_header_entry_size: header.program_header_entry_size,
        program_header_count: header.program_header_count,
        load_segments,
        interpreter,
        tls,
    })
}

pub const ET_DYN: u16 = 3;

#[derive(Debug)]
pub struct ElfImage {
    pub ty: u16,
    pub entry: u64,
    pub machine: u16,
    pub program_header_offset: u64,
    pub program_header_entry_size: usize,
    pub program_header_count: u16,
    pub load_segments: Vec<LoadSegment>,
    pub interpreter: Option<alloc::string::String>,
    pub tls: Option<TlsInfo>,
}

#[derive(Debug)]
pub struct TlsInfo {
    pub file_offset: u64,
    pub virtual_addr: u64,
    pub file_size: u64,
    pub memory_size: u64,
}

#[derive(Debug)]
pub struct LoadSegment {
    pub file_offset: u64,
    pub virtual_addr: u64,
    pub file_size: u64,
    pub memory_size: u64,
    pub flags: u32,
    pub align: u64,
}

struct ElfHeader {
    ty: u16,
    machine: u16,
    entry: u64,
    program_header_offset: u64,
    program_header_entry_size: usize,
    program_header_count: u16,
}

impl ElfHeader {
    fn parse(bytes: &[u8]) -> Result<Self, ElfError> {
        if bytes.len() < 64 {
            return Err(ElfError::Truncated);
        }
        if &bytes[..4] != b"\x7fELF" {
            return Err(ElfError::BadMagic);
        }
        if bytes[EI_CLASS] != ELFCLASS64 || bytes[EI_DATA] != ELFDATA2LSB {
            return Err(ElfError::Unsupported);
        }

        let program_header_entry_size = read_u16(bytes, 54) as usize;
        if program_header_entry_size < 56 {
            return Err(ElfError::InvalidHeader);
        }

        Ok(Self {
            ty: read_u16(bytes, 16),
            machine: read_u16(bytes, 18),
            entry: read_u64(bytes, 24),
            program_header_offset: read_u64(bytes, 32),
            program_header_entry_size,
            program_header_count: read_u16(bytes, 56),
        })
    }
}

struct ProgramHeader {
    ty: u32,
    flags: u32,
    offset: u64,
    vaddr: u64,
    file_size: u64,
    memory_size: u64,
    align: u64,
}

impl ProgramHeader {
    fn parse(bytes: &[u8]) -> Result<Self, ElfError> {
        if bytes.len() < 56 {
            return Err(ElfError::Truncated);
        }
        Ok(Self {
            ty: read_u32(bytes, 0),
            flags: read_u32(bytes, 4),
            offset: read_u64(bytes, 8),
            vaddr: read_u64(bytes, 16),
            file_size: read_u64(bytes, 32),
            memory_size: read_u64(bytes, 40),
            align: read_u64(bytes, 48),
        })
    }
}

#[derive(Debug)]
pub enum ElfError {
    Fs(fs::FsError),
    BadMagic,
    Unsupported,
    InvalidHeader,
    Truncated,
}

fn read_u16(bytes: &[u8], offset: usize) -> u16 {
    u16::from_le_bytes([bytes[offset], bytes[offset + 1]])
}

fn read_u32(bytes: &[u8], offset: usize) -> u32 {
    u32::from_le_bytes([
        bytes[offset],
        bytes[offset + 1],
        bytes[offset + 2],
        bytes[offset + 3],
    ])
}

fn read_u64(bytes: &[u8], offset: usize) -> u64 {
    u64::from_le_bytes([
        bytes[offset],
        bytes[offset + 1],
        bytes[offset + 2],
        bytes[offset + 3],
        bytes[offset + 4],
        bytes[offset + 5],
        bytes[offset + 6],
        bytes[offset + 7],
    ])
}

