#[derive(Debug)]
pub struct UserTask {
    pub id: TaskId,
    pub state: UserTaskState,
    pub image: UserImage,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct TaskId(pub u64);

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum UserTaskState {
    Ready,
    Running,
    Waiting,
    Exited(i32),
}

#[derive(Debug)]
pub struct UserImage {
    pub entry: u64,
    pub machine: u16,
    pub load_bias: usize,
    pub interpreter_path: Option<String>,
    pub interpreter: Option<Box<UserImage>>,
    pub program_header_offset: u64,
    pub program_header_entry_size: usize,
    pub program_header_count: u16,
    pub segments: Vec<UserSegment>,
    pub tls: Option<elf::TlsInfo>,
}

impl UserImage {
    fn from_elf(image: elf::ElfImage) -> Self {
        let load_bias = if image.ty == elf::ET_DYN
            && image.load_segments.iter().any(|segment| segment.virtual_addr < address_space::USER_LOAD_BASE as u64)
        {
            address_space::USER_LOAD_BASE
        } else {
            0
        };
        Self::from_elf_with_bias(image, load_bias)
    }

    pub fn from_elf_with_bias(image: elf::ElfImage, load_bias: usize) -> Self {
        let interpreter_path = image.interpreter.clone();
        let segments = image
            .load_segments
            .into_iter()
            .map(|segment| UserSegment {
                file_offset: segment.file_offset,
                virtual_addr: segment.virtual_addr,
                file_size: segment.file_size,
                memory_size: segment.memory_size,
                flags: segment.flags,
                align: segment.align,
            })
            .collect();

        Self {
            entry: image.entry,
            machine: image.machine,
            load_bias,
            interpreter_path,
            interpreter: None,
            program_header_offset: image.program_header_offset,
            program_header_entry_size: image.program_header_entry_size,
            program_header_count: image.program_header_count,
            segments,
            tls: image.tls,
        }
    }
    pub fn runtime_entry(&self) -> usize {
        self.load_bias + self.entry as usize
    }

    pub fn entry_for_exec(&self) -> usize {
        self.interpreter
            .as_ref()
            .map(|interpreter| interpreter.runtime_entry())
            .unwrap_or_else(|| self.runtime_entry())
    }

    pub fn program_header_vaddr(&self) -> usize {
        for segment in &self.segments {
            let start = segment.file_offset;
            let end = start.saturating_add(segment.file_size);
            if start <= self.program_header_offset && self.program_header_offset < end {
                return self.load_bias
                    + segment.virtual_addr as usize
                    + (self.program_header_offset - segment.file_offset) as usize;
            }
        }
        self.load_bias + self.program_header_offset as usize
    }

    pub fn brk_start(&self) -> usize {
        let mut image_end = 0usize;
        for segment in &self.segments {
            image_end = image_end.max(self.load_bias + segment.virtual_addr as usize + segment.memory_size as usize);
        }
        luwu_common::paging::align_up(image_end)
    }

    pub fn prepare_address_space(&self) -> Result<address_space::AddressSpace, UserError> {
        let mut space = address_space::AddressSpace::new_user().map_err(UserError::AddressSpace)?;
        self.reserve_segments(&mut space)?;
        if let Some(interpreter) = &self.interpreter {
            interpreter.reserve_segments(&mut space)?;
        }

        // 先预留一小段 brk 区，避免 libc 初始化 heap 时写到未映射页。
        space
            .reserve_user_range(
                self.brk_start(),
                address_space::USER_BRK_RESERVE_SIZE,
                address_space::MapPerm::READ
                    .union(address_space::MapPerm::WRITE)
                    .union(address_space::MapPerm::USER),
            )
            .map_err(UserError::AddressSpace)?;
        // 早期 mmap 先预映射一小段匿名区，支撑 libc/busybox 初始化。
        space
            .reserve_user_range(
                address_space::USER_MMAP_BASE,
                address_space::USER_EARLY_MMAP_SIZE,
                address_space::MapPerm::READ
                    .union(address_space::MapPerm::WRITE)
                    .union(address_space::MapPerm::USER),
            )
            .map_err(UserError::AddressSpace)?;
        Ok(space)
    }

    fn reserve_segments(&self, space: &mut address_space::AddressSpace) -> Result<(), UserError> {
        for segment in &self.segments {
            let perm = segment.map_perm();
            space
                .reserve_user_range(self.load_bias + segment.virtual_addr as usize, segment.memory_size as usize, perm)
                .map_err(UserError::AddressSpace)?;
        }
        Ok(())
    }
}

#[derive(Debug)]
pub struct UserSegment {
    pub file_offset: u64,
    pub virtual_addr: u64,
    pub file_size: u64,
    pub memory_size: u64,
    pub flags: u32,
    pub align: u64,
}

impl UserSegment {
    pub fn map_perm(&self) -> address_space::MapPerm {
        let mut perm = address_space::MapPerm::USER;
        if self.flags & 0x4 != 0 {
            perm = perm.union(address_space::MapPerm::READ);
        }
        if self.flags & 0x2 != 0 {
            perm = perm.union(address_space::MapPerm::WRITE);
        }
        if self.flags & 0x1 != 0 {
            perm = perm.union(address_space::MapPerm::EXECUTE);
        }
        perm
    }
}

#[derive(Debug)]
pub enum UserError {
    Elf(elf::ElfError),
    AddressSpace(address_space::AddressSpaceError),
}

