static KERNEL_RESUME_EPC: AtomicUsize = AtomicUsize::new(0);

pub fn set_kernel_resume_epc(epc: usize) {
    KERNEL_RESUME_EPC.store(epc, Ordering::SeqCst);
}

pub fn resume_kernel_epc() -> usize {
    KERNEL_RESUME_EPC.load(Ordering::SeqCst)
}

pub fn report_unhandled<A: KernelArch>(frame: TrapFrame) -> ! {
    report_decoded_unhandled::<A>(A::decode_trap_cause(frame.raw_cause), frame)
}

pub fn handle_trap<A: KernelArch + crate::ArchUserPaging + crate::ArchUser + 'static>(
    frame: TrapFrame,
) {
    match A::decode_trap_cause(frame.raw_cause) {
        TrapCause::Interrupt(InterruptKind::Timer | InterruptKind::SupervisorTimer) => {
            // timer trap 只更新时钟并唤醒到期任务；架构侧负责清中断/重装下一次 tick。
            A::handle_timer_interrupt();
            async_rt::on_timer_tick();
            process::check_expired_alarms::<A>();
        }
        TrapCause::Exception(ExceptionKind::UserEnvCall | ExceptionKind::Syscall) => {
            let syscall = syscall::SyscallFrame::new(
                A::decode_syscall_number(&frame),
                A::decode_syscall_args(&frame),
            );
            match syscall::dispatch::<A>(&frame, syscall) {
                syscall::SyscallOutcome::Return(value) => {
                    A::write_syscall_return(&frame, value);
                    A::advance_syscall_epc(&frame, 4);
                }
                syscall::SyscallOutcome::Exit(code) => {
                    console::write_fmt::<A>(format_args!(
                        "syscall: pid={} exited code={}\n",
                        process::current_pid(),
                        code
                    ));
                    if process::current_pid() == 1 {
                        A::resume_to_kernel(resume_kernel_epc());
                    }
                    process::exit_current(code);
                    process::wake_waiting_parent::<A>(process::current_pid(), code);
                }
            }
        }
        TrapCause::Exception(kind) if A::trap_from_user(&frame) => {
            handle_user_exception::<A>(kind, frame)
        }
        cause => report_decoded_unhandled::<A>(cause, frame),
    }
}

