fn signal_for_exception(kind: ExceptionKind) -> usize {
    match kind {
        ExceptionKind::IllegalInstruction | ExceptionKind::InstructionPrivilege => 4,
        ExceptionKind::Breakpoint => 5,
        ExceptionKind::FloatingPointError => 8,
        ExceptionKind::InstructionAddressMisaligned
        | ExceptionKind::LoadAddressMisaligned
        | ExceptionKind::StoreAddressMisaligned
        | ExceptionKind::InstructionAccessFault
        | ExceptionKind::LoadAccessFault
        | ExceptionKind::StoreAccessFault
        | ExceptionKind::AddressAlignment
        | ExceptionKind::AddressError => 7,
        _ => 11,
    }
}

