use core::alloc::{GlobalAlloc, Layout};
use core::cell::UnsafeCell;
use core::mem::{align_of, size_of};
use core::ptr::null_mut;

use crate::{KernelArch, console};

const HEAP_SIZE: usize = crate::address_space::KERNEL_HEAP_MIN_SIZE;
const BLOCK_ALIGN: usize = align_of::<FreeBlock>();
const MIN_BLOCK_SIZE: usize = size_of::<FreeBlock>();

#[repr(align(4096))]
struct HeapStorage(UnsafeCell<[u8; HEAP_SIZE]>);

unsafe impl Sync for HeapStorage {}

static HEAP: HeapStorage = HeapStorage(UnsafeCell::new([0; HEAP_SIZE]));

#[repr(C)]
struct FreeBlock {
    size: usize,
    next: *mut FreeBlock,
}

pub struct FreeListAllocator {
    head: UnsafeCell<FreeBlock>,
}

unsafe impl Sync for FreeListAllocator {}

unsafe impl GlobalAlloc for FreeListAllocator {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        unsafe { self.alloc_inner(layout) }
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        if ptr.is_null() {
            return;
        }
        let size = adjust_size(layout);
        unsafe {
            self.dealloc_inner(ptr, size);
        }
    }
}

impl FreeListAllocator {
    const fn new() -> Self {
        Self {
            head: UnsafeCell::new(FreeBlock {
                size: 0,
                next: null_mut(),
            }),
        }
    }

    unsafe fn init(&self, start: usize, size: usize) {
        unsafe {
            let block = start as *mut FreeBlock;
            (*block).size = align_down(size, BLOCK_ALIGN);
            (*block).next = null_mut();
            (*self.head.get()).next = block;
        }
    }

    unsafe fn alloc_inner(&self, layout: Layout) -> *mut u8 {
        let size = adjust_size(layout);
        let align = layout.align().max(BLOCK_ALIGN);
        let mut prev = self.head.get();

        while unsafe { !(*prev).next.is_null() } {
            let block = unsafe { (*prev).next };
            let block_start = block as usize;
            let block_size = unsafe { (*block).size };
            let block_end = block_start + block_size;
            let alloc_start = align_up(block_start, align);
            let alloc_end = alloc_start.saturating_add(size);

            if alloc_end <= block_end {
                let front = alloc_start - block_start;
                let back = block_end - alloc_end;

                if front >= MIN_BLOCK_SIZE && back >= MIN_BLOCK_SIZE {
                    unsafe {
                        (*block).size = front;
                        let back_block = alloc_end as *mut FreeBlock;
                        (*back_block).size = back;
                        (*back_block).next = (*block).next;
                        (*block).next = back_block;
                    }
                } else if front >= MIN_BLOCK_SIZE {
                    unsafe {
                        (*block).size = front;
                    }
                } else if back >= MIN_BLOCK_SIZE {
                    unsafe {
                        let back_block = alloc_end as *mut FreeBlock;
                        (*back_block).size = back;
                        (*back_block).next = (*block).next;
                        (*prev).next = back_block;
                    }
                } else {
                    unsafe {
                        (*prev).next = (*block).next;
                    }
                }

                return alloc_start as *mut u8;
            }

            prev = block;
        }

        null_mut()
    }

    unsafe fn dealloc_inner(&self, ptr: *mut u8, size: usize) {
        let block_start = ptr as usize;
        let mut block_size = size;
        let mut prev = self.head.get();

        while unsafe { !(*prev).next.is_null() && ((*prev).next as usize) < block_start } {
            prev = unsafe { (*prev).next };
        }

        let next = unsafe { (*prev).next };

        if prev != self.head.get() {
            let prev_end = prev as usize + unsafe { (*prev).size };
            if prev_end == block_start {
                block_size += unsafe { (*prev).size };
                unsafe {
                    (*prev).size = block_size;
                }
            } else {
                let block = block_start as *mut FreeBlock;
                unsafe {
                    (*block).size = block_size;
                    (*block).next = next;
                    (*prev).next = block;
                }
                prev = block;
            }
        } else {
            let block = block_start as *mut FreeBlock;
            unsafe {
                (*block).size = block_size;
                (*block).next = next;
                (*prev).next = block;
            }
            prev = block;
        }

        let next = unsafe { (*prev).next };
        let prev_end = prev as usize + unsafe { (*prev).size };
        if !next.is_null() && prev_end == next as usize {
            unsafe {
                (*prev).size += (*next).size;
                (*prev).next = (*next).next;
            }
        }
    }
}

#[global_allocator]
static GLOBAL_ALLOCATOR: FreeListAllocator = FreeListAllocator::new();

pub fn init<A: KernelArch>() {
    let start = HEAP.0.get() as *mut u8 as usize;
    let end = start + HEAP_SIZE;
    unsafe {
        GLOBAL_ALLOCATOR.init(start, HEAP_SIZE);
    }
    console::write_fmt::<A>(format_args!(
        "alloc: heap [{:#x}, {:#x})\n",
        start, end
    ));
}

#[alloc_error_handler]
fn alloc_error(layout: Layout) -> ! {
    panic!("alloc error: size={} align={}", layout.size(), layout.align())
}

fn adjust_size(layout: Layout) -> usize {
    align_up(layout.size().max(MIN_BLOCK_SIZE), BLOCK_ALIGN)
}

const fn align_up(value: usize, align: usize) -> usize {
    (value + align - 1) & !(align - 1)
}

const fn align_down(value: usize, align: usize) -> usize {
    value & !(align - 1)
}

use alloc::vec::Vec;

use luwu_common::paging::{PAGE_SIZE, align_down, align_up};

// 用户地址空间的基础布局：
// - 低地址留给 ELF text/data/bss，便于装载和排错；
// - 中间留给 mmap/dlopen 之类的扩展区；
// - 高地址留给向下增长的用户栈；
// - 内核 heap 只作为资源上限提示，不直接参与用户映射。
pub const KERNEL_HEAP_MIN_SIZE: usize = 64 * 1024 * 1024;
pub const USER_STACK_SIZE: usize = 8 * 1024 * 1024;
pub const USER_STACK_TOP: usize = 0x0000_003f_ffff_f000;
pub const USER_MMAP_BASE: usize = 0x0000_0020_0000_0000;
pub const USER_INTERP_BASE: usize = 0x0000_0001_0000_0000;
pub const USER_MMAP_SIZE: usize = 0x0000_0010_0000_0000;
pub const USER_EARLY_MMAP_SIZE: usize = 2 * 1024 * 1024;
pub const USER_BRK_RESERVE_SIZE: usize = 2 * 1024 * 1024;
pub const USER_LOAD_BASE: usize = 0x0000_0000_0001_0000;
pub const USER_TLS_AREA_BASE: usize = USER_STACK_TOP - USER_STACK_SIZE - PAGE_SIZE * 2;
pub const USER_MAX: usize = USER_STACK_TOP;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct VirtRange {
    pub start: usize,
    pub end: usize,
}

impl VirtRange {
    pub fn page_aligned(start: usize, len: usize) -> Result<Self, AddressSpaceError> {
        let end = start.checked_add(len).ok_or(AddressSpaceError::Overflow)?;
        Ok(Self {
            start: align_down(start),
            end: align_up(end),
        })
    }

    pub fn len(&self) -> usize {
        self.end.saturating_sub(self.start)
    }

    pub fn is_empty(&self) -> bool {
        self.start >= self.end
    }

    pub fn contains(&self, addr: usize) -> bool {
        self.start <= addr && addr < self.end
    }

    pub fn overlaps(&self, other: Self) -> bool {
        self.start < other.end && other.start < self.end
    }
}

// 页权限只是“布局层”的抽象，不直接等同于架构 PTE 位。
// 具体的 RISC-V / LoongArch 转换在各自 arch crate 里完成。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct MapPerm {
    bits: u8,
}

impl MapPerm {
    pub const READ: Self = Self { bits: 1 << 0 };
    pub const WRITE: Self = Self { bits: 1 << 1 };
    pub const EXECUTE: Self = Self { bits: 1 << 2 };
    pub const USER: Self = Self { bits: 1 << 3 };

    pub const fn empty() -> Self {
        Self { bits: 0 }
    }

    pub const fn from_bits(bits: u8) -> Self {
        Self { bits }
    }

    pub const fn to_user_flags(self) -> luwu_common::UserMapFlags {
        let mut flags = luwu_common::UserMapFlags::empty();
        if self.contains(Self::READ) {
            flags = flags.union(luwu_common::UserMapFlags::READ);
        }
        if self.contains(Self::WRITE) {
            flags = flags.union(luwu_common::UserMapFlags::WRITE);
        }
        if self.contains(Self::EXECUTE) {
            flags = flags.union(luwu_common::UserMapFlags::EXECUTE);
        }
        if self.contains(Self::USER) {
            flags = flags.union(luwu_common::UserMapFlags::USER);
        }
        flags
    }

    pub const fn bits(self) -> u8 {
        self.bits
    }

    pub const fn contains(self, perm: Self) -> bool {
        self.bits & perm.bits == perm.bits
    }

    pub const fn union(self, perm: Self) -> Self {
        Self {
            bits: self.bits | perm.bits,
        }
    }
}

#[derive(Clone, Debug)]
pub struct UserMapping {
    pub range: VirtRange,
    pub perm: MapPerm,
}

#[derive(Debug)]
pub struct AddressSpace {
    mappings: Vec<UserMapping>,
    stack: VirtRange,
    mmap: VirtRange,
}

impl AddressSpace {
    pub fn new_user() -> Result<Self, AddressSpaceError> {
        let stack = VirtRange::page_aligned(USER_STACK_TOP - USER_STACK_SIZE, USER_STACK_SIZE)?;
        let mmap = VirtRange::page_aligned(USER_MMAP_BASE, USER_MMAP_SIZE)?;
        let mut space = Self {
            mappings: Vec::new(),
            stack,
            mmap,
        };
        // 先把用户栈预留进去，后续 ELF、mmap、brk 才不会误撞栈区。
        space.mappings.push(UserMapping {
            range: stack,
            perm: MapPerm::READ.union(MapPerm::WRITE).union(MapPerm::USER),
        });
        Ok(space)
    }

    pub fn reserve_user_range(
        &mut self,
        start: usize,
        len: usize,
        perm: MapPerm,
    ) -> Result<VirtRange, AddressSpaceError> {
        let range = VirtRange::page_aligned(start, len)?;
        self.validate_user_range(range)?;
        if self.mappings.iter().any(|mapping| mapping.range.overlaps(range)) {
            return Err(AddressSpaceError::Overlap);
        }
        self.mappings.push(UserMapping { range, perm });
        Ok(range)
    }

    pub fn stack_range(&self) -> VirtRange {
        self.stack
    }

    pub fn mmap_range(&self) -> VirtRange {
        self.mmap
    }

    pub fn mappings(&self) -> &[UserMapping] {
        &self.mappings
    }

    fn validate_user_range(&self, range: VirtRange) -> Result<(), AddressSpaceError> {
        // 这里先只接受页对齐、位于用户范围内且不为空的区间。
        // 真正的访问权限与 copy_from_user 检查后面会再细化。
        if range.is_empty() || range.start < USER_LOAD_BASE || range.end > USER_MAX {
            return Err(AddressSpaceError::OutOfUserRange);
        }
        if range.start % PAGE_SIZE != 0 || range.end % PAGE_SIZE != 0 {
            return Err(AddressSpaceError::Unaligned);
        }
        Ok(())
    }
}

#[derive(Debug)]
pub enum AddressSpaceError {
    Overflow,
    Unaligned,
    OutOfUserRange,
    Overlap,
}

use core::fmt::{self, Write};
