use crate::{KernelArch, async_rt};

pub struct Writer<A: KernelArch> {
    inner: A::Console,
}

impl<A: KernelArch> Writer<A> {
    #[inline]
    pub fn new() -> Self {
        Self {
            inner: A::early_console(),
        }
    }
}

impl<A: KernelArch> Write for Writer<A> {
    #[inline]
    fn write_str(&mut self, s: &str) -> fmt::Result {
        self.inner.write_bytes(s.as_bytes());
        Ok(())
    }
}

#[inline]
pub fn init<A: KernelArch>() {
    // 现在的 early console 没有全局状态；调用一次主要是让启动流程显式经过 console init。
    // 以后如果串口需要设置 baud/divisor，可以把初始化放到架构实现里。
    let _ = A::early_console();
}

#[inline]
pub fn write_str<A: KernelArch>(s: &str) {
    let mut console = Writer::<A>::new();
    console.write_str(s).ok();
}

#[inline]
pub fn write_byte<A: KernelArch>(byte: u8) {
    let mut console = A::early_console();
    console.write_byte(byte);
}

#[inline]
pub fn write_fmt<A: KernelArch>(args: fmt::Arguments<'_>) {
    let mut console = Writer::<A>::new();
    console.write_fmt(args).ok();
}

#[inline]
pub fn read_byte<A: KernelArch>() -> Option<u8> {
    let mut console = A::early_console();
    console.get_byte()
}

pub async fn read_byte_async<A: KernelArch>() -> u8 {
    loop {
        if let Some(byte) = read_byte::<A>() {
            return byte;
        }
        async_rt::sleep_ticks(1).await;
    }
}

#[inline]
pub fn read_byte_blocking<A: KernelArch>() -> u8 {
    loop {
        if let Some(byte) = read_byte::<A>() {
            return byte;
        }
        // 没输入时不要空转烧 CPU。timer interrupt 打开后这里也能被 tick 唤醒再继续轮询。
        A::wait_for_interrupt();
    }
}

use crate::{KernelArch, console};

const COMMAND_BUFFER_LEN: usize = 32;

pub async fn run<A: KernelArch>() -> ! {
    // 这是临时 monitor，不是完整 shell。它的价值是验证串口 RX/TX、
    // paging 后的 MMIO 映射，以及架构 reboot/poweroff 路径。
    console::write_str::<A>("luwu: console ready\n");

    loop {
        console::write_str::<A>("luwu> ");
        let mut line = [0u8; COMMAND_BUFFER_LEN];
        let len = read_line::<A>(&mut line).await;
        let command = &line[..len];

        if command == b"reboot" {
            console::write_str::<A>("rebooting...\n");
            A::reboot();
        } else if command == b"poweroff" {
            console::write_str::<A>("powering off...\n");
            A::poweroff();
        } else if command.is_empty() {
            continue;
        } else {
            console::write_str::<A>("unknown command\n");
        }
    }
}

async fn read_line<A: KernelArch>(buffer: &mut [u8; COMMAND_BUFFER_LEN]) -> usize {
    let mut len = 0;

    loop {
        match console::read_byte_async::<A>().await {
            b'\r' | b'\n' => {
                console::write_str::<A>("\n");
                return len;
            }
            8 | 127 => {
                // 兼容 Backspace 和 DEL，两种终端都会见到。
                if len > 0 {
                    len -= 1;
                    console::write_str::<A>("\x08 \x08");
                }
            }
            byte if byte.is_ascii_graphic() || byte == b' ' => {
                // 缓冲区满时继续吞输入但不回显，直到用户按回车。
                if len < buffer.len() {
                    buffer[len] = byte;
                    len += 1;
                    console::write_byte::<A>(byte);
                }
            }
            _ => {}
        }
    }
}

