};

pub type VirtioExt4<A> = Ext4FileSystem<Ext4BlockAdapter<A>>;

pub fn mount_first_ext4<A: KernelArch>() -> Result<VirtioExt4<A>, MountError> {
    let device = blk::VirtioBlk::<A>::probe_first().ok_or(MountError::NoBlockDevice)?;
    let capacity = device.capacity_sectors();
    let adapter = Ext4BlockAdapter::<A>::new(device, capacity);
    Ext4FileSystem::mount(adapter, false).map_err(MountError::Ext4)
}

#[derive(Debug)]
pub enum MountError {
    NoBlockDevice,
    Ext4(Ext4Error),
}

pub struct Ext4BlockAdapter<A: KernelArch> {
    device: UnsafeCell<blk::VirtioBlk<A>>,
    capacity_sectors: u64,
}

impl<A: KernelArch> Ext4BlockAdapter<A> {
    pub fn new(device: blk::VirtioBlk<A>, capacity_sectors: u64) -> Self {
        Self {
            device: UnsafeCell::new(device),
            capacity_sectors,
        }
    }
}

impl<A: KernelArch> BlockDevice for Ext4BlockAdapter<A> {
    fn read_block(&self, block_no: u64, buf: &mut [u8]) -> Result<(), Ext4Error> {
        if buf.len() % 512 != 0 {
            return Err(Ext4Error::IoError);
        }

        let first_sector = block_no
            .checked_mul((buf.len() / 512) as u64)
            .ok_or(Ext4Error::OutOfBounds)?;
        let sectors = (buf.len() / 512) as u64;
        if first_sector + sectors > self.capacity_sectors {
            return Err(Ext4Error::OutOfBounds);
        }

        for (index, chunk) in buf.chunks_exact_mut(512).enumerate() {
            let sector_buf = sector_array_mut(chunk)?;
            let result = unsafe {
                // luwu-ext4 的只读核心当前是同步接口；这里把一次 ext4 block read
                // 拆成若干 512B sector future，并在启动期临时执行器里跑完。
                let device = &mut *self.device.get();
                async_rt::block_on::<A, _>(blk::read_sector(
                    device,
                    first_sector + index as u64,
                    sector_buf,
                ))
            };
            map_block_result(result)?;
        }
        Ok(())
    }

    fn write_block(&mut self, block_no: u64, buf: &[u8]) -> Result<(), Ext4Error> {
        if buf.len() % 512 != 0 {
            return Err(Ext4Error::IoError);
        }

        let first_sector = block_no
            .checked_mul((buf.len() / 512) as u64)
            .ok_or(Ext4Error::OutOfBounds)?;
        let sectors = (buf.len() / 512) as u64;
        if first_sector + sectors > self.capacity_sectors {
            return Err(Ext4Error::OutOfBounds);
        }

        for (index, chunk) in buf.chunks_exact(512).enumerate() {
            let sector_buf = sector_array(chunk)?;
            let result = unsafe {
                let device = &mut *self.device.get();
                async_rt::block_on::<A, _>(blk::write_sector(
                    device,
                    first_sector + index as u64,
                    sector_buf,
                ))
            };
            map_block_result(result)?;
        }
        Ok(())
    }

    fn block_size(&self) -> usize {
        1024
    }

    fn total_blocks(&self) -> u64 {
        self.capacity_sectors / 2
    }
}

fn sector_array(chunk: &[u8]) -> Result<&[u8; 512], Ext4Error> {
    chunk.try_into().map_err(|_| Ext4Error::IoError)
}

fn sector_array_mut(chunk: &mut [u8]) -> Result<&mut [u8; 512], Ext4Error> {
    chunk.try_into().map_err(|_| Ext4Error::IoError)
}

fn map_block_result(result: BlockResult<()>) -> Result<(), Ext4Error> {
    match result {
        Ok(()) => Ok(()),
        Err(BlockError::Unsupported | BlockError::NoDevice | BlockError::QueueUnavailable) => {
            Err(Ext4Error::IncompatibleFeature(0))
        }
        Err(BlockError::InvalidBuffer | BlockError::Busy | BlockError::DeviceError | BlockError::Io) => {
            Err(Ext4Error::IoError)
        }
    }
}

impl From<mmio::VirtioMmioError> for BlockError {
    fn from(error: mmio::VirtioMmioError) -> Self {
        match error {
            mmio::VirtioMmioError::Unsupported => Self::Unsupported,
            mmio::VirtioMmioError::QueueUnavailable => Self::QueueUnavailable,
            mmio::VirtioMmioError::DeviceError => Self::DeviceError,
        }
    }
}

impl From<pci::VirtioPciError> for BlockError {
    fn from(error: pci::VirtioPciError) -> Self {
        match error {
            pci::VirtioPciError::Unsupported => Self::Unsupported,
            pci::VirtioPciError::QueueUnavailable => Self::QueueUnavailable,
            pci::VirtioPciError::DeviceError => Self::DeviceError,
        }
    }
}

