}

#[repr(C, align(4096))]
struct DmaStorage {
    queue: QueueStorage,
    header: BlkRequestHeader,
    status: u8,
    data: [u8; 512],
}

impl DmaStorage {
    const fn new() -> Self {
        Self {
            queue: QueueStorage::new(),
            header: BlkRequestHeader {
                request_type: 0,
                reserved: 0,
                sector: 0,
            },
            status: 0xff,
            data: [0; 512],
        }
    }
