struct GlobalDmaStorage {
    inner: UnsafeCell<DmaStorage>,
}

unsafe impl Sync for GlobalDmaStorage {}

// 设备会保存 descriptor、请求头和 status byte 的物理地址。把它们放在
// 稳定的 static 对象里，可以避免 Rust 结构体 move 之后，设备仍然持有旧地址的
// 经典问题。当前驱动只支持一个 outstanding request，所以一个 storage slot 足够。
static DMA_STORAGE: GlobalDmaStorage = GlobalDmaStorage {
    inner: UnsafeCell::new(DmaStorage::new()),
};

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum RequestState {
    Idle,
    Submitted {
        last_used_idx: u16,
        buffer_addr: usize,
        buffer_len: usize,
        device_writes_buffer: bool,
    },
}

enum VirtioTransport {
    Mmio(VirtioMmioTransport),
    Pci(VirtioPciTransport),
}

pub struct VirtioBlk<A: KernelArch> {
    transport: VirtioTransport,
    request_state: RequestState,
    _arch: PhantomData<A>,
}

impl VirtioTransport {
    fn setup_queue(
        &self,
        queue_index: u32,
        queue_size: u16,
        desc: u64,
        driver: u64,
        device: u64,
    ) -> BlockResult<()> {
        match self {
            Self::Mmio(transport) => transport
                .setup_queue(queue_index, queue_size, desc, driver, device)
                .map_err(BlockError::from),
            Self::Pci(transport) => transport
                .setup_queue(queue_index, queue_size, desc, driver, device)
                .map_err(BlockError::from),
        }
    }

    fn capacity_sectors(&self) -> u64 {
        match self {
            Self::Mmio(transport) => transport.capacity_sectors(),
            Self::Pci(transport) => transport.capacity_sectors(),
        }
    }

    fn notify_queue(&self, queue_index: u32) {
        match self {
            Self::Mmio(transport) => transport.notify_queue(queue_index),
            Self::Pci(transport) => transport.notify_queue(queue_index),
        }
    }

    fn ack_interrupts(&self) {
        match self {
            Self::Mmio(transport) => transport.ack_interrupts(),
            Self::Pci(transport) => transport.ack_interrupts(),
        }
    }
}

impl<A: KernelArch> VirtioBlk<A> {
    pub fn probe_first() -> Option<Self> {
        let mut regions = [MmioRegion { base: 0, size: 0 }; 16];
        let count = A::virtio_mmio_regions(&mut regions);

        for region in regions.iter().take(count) {
            let Some(transport) = VirtioMmioTransport::probe(*region) else {
                continue;
            };

            let mut device = Self {
                transport: VirtioTransport::Mmio(transport),
                request_state: RequestState::Idle,
                _arch: PhantomData,
            };

            if device.init_queue().is_ok() {
                return Some(device);
            }
        }

        if let Some(transport) = VirtioPciTransport::probe_first::<A>() {
            let mut device = Self {
                transport: VirtioTransport::Pci(transport),
                request_state: RequestState::Idle,
                _arch: PhantomData,
            };
            if device.init_queue().is_ok() {
                return Some(device);
            }
        }

        None
    }

    pub fn capacity_sectors(&self) -> u64 {
        self.transport.capacity_sectors()
    }

    fn storage() -> *mut DmaStorage {
        DMA_STORAGE.inner.get()
    }

    fn dma_storage() -> *mut DmaStorage {
        A::dma_virt_to_virt(Self::storage() as usize) as *mut DmaStorage
    }

    fn init_queue(&mut self) -> BlockResult<()> {
        let storage = Self::storage();
        let dma_storage = Self::dma_storage();
        unsafe {
            (*dma_storage).queue.reset();
            // virtio-mmio 寄存器需要物理地址。当前 RISC-V 是 identity map，
            // LoongArch 则通过架构层处理 DMW 高低地址转换。generic 驱动不关心
            // 具体平台策略。
            let desc = A::virt_to_phys((&(*storage).queue.desc as *const _) as usize) as u64;
            let avail = A::virt_to_phys((&(*storage).queue.avail as *const _) as usize) as u64;
            let used = A::virt_to_phys((&(*storage).queue.used as *const _) as usize) as u64;
            self.transport.setup_queue(0, QUEUE_SIZE, desc, avail, used)
        }
    }

