        self.submit_request(
            VIRTIO_BLK_T_IN,
            sector,
            buffer.as_mut_ptr() as usize,
            buffer.len(),
            true,
        )
    }

    fn submit_write(&mut self, sector: u64, buffer: &[u8; 512]) {
        self.submit_request(
            VIRTIO_BLK_T_OUT,
            sector,
            buffer.as_ptr() as usize,
            buffer.len(),
            false,
