use luwu_common::MmioRegion;

const MAGIC_VALUE: usize = 0x000;
const VERSION: usize = 0x004;
const DEVICE_ID: usize = 0x008;
const VENDOR_ID: usize = 0x00c;
const DEVICE_FEATURES: usize = 0x010;
const DEVICE_FEATURES_SEL: usize = 0x014;
const DRIVER_FEATURES: usize = 0x020;
const DRIVER_FEATURES_SEL: usize = 0x024;
const GUEST_PAGE_SIZE: usize = 0x028;
const QUEUE_SEL: usize = 0x030;
const QUEUE_NUM_MAX: usize = 0x034;
const QUEUE_NUM: usize = 0x038;
const QUEUE_ALIGN: usize = 0x03c;
const QUEUE_PFN: usize = 0x040;
const QUEUE_READY: usize = 0x044;
const QUEUE_NOTIFY: usize = 0x050;
const INTERRUPT_STATUS: usize = 0x060;
const INTERRUPT_ACK: usize = 0x064;
const STATUS: usize = 0x070;
const QUEUE_DESC_LOW: usize = 0x080;
const QUEUE_DRIVER_LOW: usize = 0x090;
const QUEUE_DEVICE_LOW: usize = 0x0a0;
const CONFIG: usize = 0x100;

const VIRTIO_MAGIC: u32 = 0x7472_6976;
const VIRTIO_VERSION_LEGACY: u32 = 1;
const VIRTIO_VERSION_MODERN: u32 = 2;
const VIRTIO_DEVICE_BLK: u32 = 2;
const VIRTIO_F_VERSION_1: u32 = 1;

const STATUS_ACKNOWLEDGE: u32 = 1;
const STATUS_DRIVER: u32 = 2;
const STATUS_DRIVER_OK: u32 = 4;
const STATUS_FEATURES_OK: u32 = 8;
const STATUS_FAILED: u32 = 128;

#[derive(Clone, Copy)]
pub struct VirtioMmioTransport {
    base: usize,
    version: u32,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum VirtioMmioError {
    Unsupported,
    QueueUnavailable,
    DeviceError,
}

impl VirtioMmioTransport {
    /// 检查架构层提供的 MMIO 窗口是否是 modern virtio-blk 设备。
    /// 设备发现留在 `KernelArch` 后面，所以 transport 不需要知道自己运行在
    /// RISC-V、LoongArch，还是其它平台。
    pub fn probe(region: MmioRegion) -> Option<Self> {
        if region.size < 0x1000 {
            return None;
        }

        let transport = Self {
            base: region.base,
            version: 0,
        };
        let version = transport.read32(VERSION);
        if transport.read32(MAGIC_VALUE) != VIRTIO_MAGIC {
            return None;
        }
        if version != VIRTIO_VERSION_LEGACY && version != VIRTIO_VERSION_MODERN {
            return None;
        }
        if transport.read32(DEVICE_ID) != VIRTIO_DEVICE_BLK {
            return None;
        }
        if transport.read32(VENDOR_ID) == 0 {
            return None;
        }
        Some(Self {
            base: region.base,
            version,
        })
    }

    pub fn setup_queue(
        &self,
        queue_index: u32,
        queue_size: u16,
        desc: u64,
        driver: u64,
        device: u64,
    ) -> Result<(), VirtioMmioError> {
        if self.version == VIRTIO_VERSION_LEGACY {
            self.setup_queue_legacy(queue_index, queue_size, desc)
        } else {
            self.setup_queue_modern(queue_index, queue_size, desc, driver, device)
        }
    }

    fn setup_queue_modern(
        &self,
        queue_index: u32,
        queue_size: u16,
        desc: u64,
        driver: u64,
        device: u64,
    ) -> Result<(), VirtioMmioError> {
        // modern virtio 初始化顺序：reset -> ACKNOWLEDGE -> DRIVER ->
        // feature negotiation -> queue setup -> DRIVER_OK。当前不启用可选
        // feature，已经足够支撑只读 virtio-blk 请求路径。
        self.write32(STATUS, 0);
        self.write32(STATUS, STATUS_ACKNOWLEDGE);
        self.write32(STATUS, STATUS_ACKNOWLEDGE | STATUS_DRIVER);

        self.write32(DEVICE_FEATURES_SEL, 0);
        let _device_features_low = self.read32(DEVICE_FEATURES);
        self.write32(DEVICE_FEATURES_SEL, 1);
        let device_features_high = self.read32(DEVICE_FEATURES);
        if (device_features_high & VIRTIO_F_VERSION_1) == 0 {
            self.write32(STATUS, STATUS_FAILED);
            return Err(VirtioMmioError::Unsupported);
        }
        self.write32(DRIVER_FEATURES_SEL, 0);
        self.write32(DRIVER_FEATURES, 0);
        self.write32(DRIVER_FEATURES_SEL, 1);
        self.write32(DRIVER_FEATURES, VIRTIO_F_VERSION_1);

        let mut status = STATUS_ACKNOWLEDGE | STATUS_DRIVER | STATUS_FEATURES_OK;
        self.write32(STATUS, status);
        status = self.read32(STATUS);
        if (status & STATUS_FEATURES_OK) == 0 {
            self.write32(STATUS, status | STATUS_FAILED);
            return Err(VirtioMmioError::Unsupported);
        }

        self.write32(QUEUE_SEL, queue_index);
        let max = self.read32(QUEUE_NUM_MAX);
        if max == 0 || max < queue_size as u32 {
            self.write32(STATUS, status | STATUS_FAILED);
            return Err(VirtioMmioError::QueueUnavailable);
        }
        if self.read32(QUEUE_READY) != 0 {
            self.write32(STATUS, status | STATUS_FAILED);
            return Err(VirtioMmioError::QueueUnavailable);
        }

        self.write32(QUEUE_NUM, queue_size as u32);
        // split virtqueue 有三块物理地址区域。VA->PA 转换由架构层负责，
        // 这样驱动层保持平台无关。
        self.write64(QUEUE_DESC_LOW, desc);
        self.write64(QUEUE_DRIVER_LOW, driver);
        self.write64(QUEUE_DEVICE_LOW, device);
        self.write32(QUEUE_READY, 1);
        self.write32(STATUS, status | STATUS_DRIVER_OK);
        Ok(())
    }

    fn setup_queue_legacy(
        &self,
        queue_index: u32,
        queue_size: u16,
        desc: u64,
    ) -> Result<(), VirtioMmioError> {
        const LEGACY_PAGE_SIZE: u32 = 4096;
        if desc & (LEGACY_PAGE_SIZE as u64 - 1) != 0 {
            return Err(VirtioMmioError::Unsupported);
        }

        self.write32(STATUS, 0);
        self.write32(STATUS, STATUS_ACKNOWLEDGE);
        self.write32(STATUS, STATUS_ACKNOWLEDGE | STATUS_DRIVER);

        self.write32(GUEST_PAGE_SIZE, LEGACY_PAGE_SIZE);
        self.write32(QUEUE_SEL, queue_index);
        let max = self.read32(QUEUE_NUM_MAX);
        if max == 0 || max < queue_size as u32 {
            self.write32(STATUS, STATUS_FAILED);
            return Err(VirtioMmioError::QueueUnavailable);
        }
        if self.read32(QUEUE_PFN) != 0 {
            self.write32(STATUS, STATUS_FAILED);
            return Err(VirtioMmioError::QueueUnavailable);
        }

        self.write32(QUEUE_NUM, queue_size as u32);
        self.write32(QUEUE_ALIGN, LEGACY_PAGE_SIZE);
        self.write32(QUEUE_PFN, (desc / LEGACY_PAGE_SIZE as u64) as u32);
        self.write32(
            STATUS,
            STATUS_ACKNOWLEDGE | STATUS_DRIVER | STATUS_DRIVER_OK,
        );
        Ok(())
    }

    #[inline]
    pub fn capacity_sectors(&self) -> u64 {
        self.read64(CONFIG)
    }

    #[inline]
    pub fn notify_queue(&self, queue_index: u32) {
        self.write32(QUEUE_NOTIFY, queue_index);
    }

    #[inline]
    pub fn ack_interrupts(&self) {
        let status = self.read32(INTERRUPT_STATUS);
        if status != 0 {
            self.write32(INTERRUPT_ACK, status);
        }
    }

    #[inline]
    fn read32(&self, offset: usize) -> u32 {
        unsafe { core::ptr::read_volatile((self.base + offset) as *const u32) }
    }

    #[inline]
    fn read64(&self, offset_low: usize) -> u64 {
        let low = self.read32(offset_low) as u64;
        let high = self.read32(offset_low + 4) as u64;
        low | (high << 32)
    }

    #[inline]
    fn write32(&self, offset: usize, value: u32) {
        unsafe {
            core::ptr::write_volatile((self.base + offset) as *mut u32, value);
        }
    }

    #[inline]
    fn write64(&self, offset_low: usize, value: u64) {
        self.write32(offset_low, value as u32);
        self.write32(offset_low + 4, (value >> 32) as u32);
    }
}

