impl VirtioPciTransport {
    pub fn probe_first<A: KernelArch>() -> Option<Self> {
        let ecam = A::pci_ecam_base()?;
        let mmio_base = A::pci_mmio32_base()?;
        let mut next_mmio = mmio_base;

        for dev in 0..32u8 {
            let function = PciFunction::<A>::new(ecam, 0, dev, 0);
            let Some(vendor) = function.vendor_id() else {
                continue;
            };
            if vendor == PCI_VENDOR_INVALID {
                continue;
            }
            let header_type = function.read8(PCI_HEADER_TYPE);
            let functions = if header_type & 0x80 != 0 { 8 } else { 1 };
            for fun in 0..functions {
                let function = PciFunction::<A>::new(ecam, 0, dev, fun);
                let Some(vendor) = function.vendor_id() else {
                    continue;
                };
                if vendor != PCI_VENDOR_VIRTIO || !function.is_virtio_blk() {
                    continue;
                }
                function.assign_memory_bars(&mut next_mmio);
                if let Some(transport) = Self::from_function(&function) {
                    function.enable_bus_master();
                    return Some(transport);
                }
            }
        }

        None
    }

    fn from_function<A: KernelArch>(function: &PciFunction<A>) -> Option<Self> {
        let mut common = None;
        let mut notify = None;
        let mut isr = None;
        let mut device = None;
        function.for_each_vendor_capability(|cap| {
            let Some(addr) = function.capability_addr(cap) else {
                return;
            };
            match cap.cfg_type {
                VIRTIO_PCI_CAP_COMMON_CFG => common = Some(addr),
                VIRTIO_PCI_CAP_NOTIFY_CFG => notify = Some((addr, cap.notify_multiplier)),
                VIRTIO_PCI_CAP_ISR_CFG => isr = Some(addr),
                VIRTIO_PCI_CAP_DEVICE_CFG => device = Some(addr),
                _ => {}
            }
        });
        let (notify, notify_multiplier) = notify?;
        Some(Self {
            common: common?,
            notify,
            notify_multiplier,
            isr: isr?,
            device: device?,
        })
    }

    pub fn setup_queue(
        &self,
        queue_index: u32,
        queue_size: u16,
        desc: u64,
        driver: u64,
        device: u64,
    ) -> Result<(), VirtioPciError> {
