        self.write_status(0);
        self.write_status(STATUS_ACKNOWLEDGE);
        self.write_status(STATUS_ACKNOWLEDGE | STATUS_DRIVER);

        self.write_common32(COMMON_DEVICE_FEATURE_SELECT, 1);
        let device_features_high = self.read_common32(COMMON_DEVICE_FEATURE);
        if (device_features_high & VIRTIO_F_VERSION_1) == 0 {
            self.write_status(self.read_status() | STATUS_FAILED);
            return Err(VirtioPciError::Unsupported);
        }
        self.write_common32(COMMON_DRIVER_FEATURE_SELECT, 0);
        self.write_common32(COMMON_DRIVER_FEATURE, 0);
        self.write_common32(COMMON_DRIVER_FEATURE_SELECT, 1);
        self.write_common32(COMMON_DRIVER_FEATURE, VIRTIO_F_VERSION_1);

        self.write_status(self.read_status() | STATUS_FEATURES_OK);
        if (self.read_status() & STATUS_FEATURES_OK) == 0 {
            self.write_status(self.read_status() | STATUS_FAILED);
            return Err(VirtioPciError::Unsupported);
        }

