pub const QUEUE_SIZE: u16 = 8;

pub const DESC_F_NEXT: u16 = 1;
pub const DESC_F_WRITE: u16 = 2;

const LEGACY_QUEUE_ALIGN: usize = 4096;
const DESC_BYTES: usize = core::mem::size_of::<Desc>() * QUEUE_SIZE as usize;
const AVAIL_BYTES: usize = core::mem::size_of::<Avail>();
const LEGACY_USED_PADDING: usize = LEGACY_QUEUE_ALIGN - DESC_BYTES - AVAIL_BYTES;

#[repr(C)]
#[derive(Clone, Copy)]
pub struct Desc {
    pub addr: u64,
    pub len: u32,
    pub flags: u16,
    pub next: u16,
}

#[repr(C)]
pub struct Avail {
    pub flags: u16,
    pub idx: u16,
    pub ring: [u16; QUEUE_SIZE as usize],
    pub used_event: u16,
}

#[repr(C)]
#[derive(Clone, Copy)]
pub struct UsedElem {
    pub id: u32,
    pub len: u32,
}

#[repr(C)]
pub struct Used {
    pub flags: u16,
    pub idx: u16,
    pub ring: [UsedElem; QUEUE_SIZE as usize],
    pub avail_event: u16,
}

#[repr(C, align(4096))]
pub struct QueueStorage {
    pub desc: [Desc; QUEUE_SIZE as usize],
    pub avail: Avail,
    // legacy virtio-mmio 只接收 queue PFN 和 queue align，used ring 必须位于
    // align(desc + avail, QUEUE_ALIGN)；modern transport 也可以继续使用这个布局。
    legacy_used_padding: [u8; LEGACY_USED_PADDING],
    pub used: Used,
}

impl QueueStorage {
    pub const fn new() -> Self {
        Self {
            desc: [Desc {
                addr: 0,
                len: 0,
                flags: 0,
                next: 0,
            }; QUEUE_SIZE as usize],
            avail: Avail {
                flags: 0,
                idx: 0,
                ring: [0; QUEUE_SIZE as usize],
                used_event: 0,
            },
            legacy_used_padding: [0; LEGACY_USED_PADDING],
            used: Used {
                flags: 0,
                idx: 0,
                ring: [UsedElem { id: 0, len: 0 }; QUEUE_SIZE as usize],
                avail_event: 0,
            },
        }
    }

    pub fn reset(&mut self) {
        *self = Self::new();
    }
}

