pub(super) fn sys_newfstatat<A: KernelArch + 'static>(
    dirfd: usize,
    path_ptr: usize,
    stat_ptr: usize,
    flags: usize,
) -> SyscallOutcome {
    const AT_EMPTY_PATH: usize = 0x1000;
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    if flags & AT_EMPTY_PATH != 0
        && process::path_from_user(memory, path_ptr).as_deref() == Some("")
    {
        return write_stat_for_fd::<A>(memory, dirfd, stat_ptr);
    }
    let path = resolve_user_path_at(memory, dirfd, path_ptr)
        .unwrap_or_else(|| alloc::string::String::from("<bad>"));
    write_stat_for_path::<A>(memory, stat_ptr, &path)
}

pub(super) fn sys_newfstat<A: KernelArch + 'static>(fd: usize, stat_ptr: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    write_stat_for_fd::<A>(memory, fd, stat_ptr)
}

fn write_stat_for_fd<A: KernelArch + 'static>(
    memory: &crate::user_paging::UserMemory,
    fd: usize,
    stat_ptr: usize,
) -> SyscallOutcome {
    if fd >= 3 && process::get_fd(fd).is_none() {
        return SyscallOutcome::Return(EBADF);
    }
    if let Some(process::FileDescriptor::Directory) =
        (fd >= 3).then(|| process::get_fd(fd)).flatten()
    {
        return write_stat(memory, stat_ptr, 0o040000 | 0o755, 1, 4096, 8);
    }
    if let Some(process::FileDescriptor::Memory { id, .. }) = process::get_fd(fd) {
        let Some(path) = memory_file_path(id) else {
            return SyscallOutcome::Return(ENOENT);
        };
        if directory_exists::<A>(&path) {
            return write_stat(memory, stat_ptr, 0o040000 | 0o755, stable_ino(&path), 4096, 8);
        }
        let size = memory_file_len(id).unwrap_or(0) as u64;
        return write_stat(memory, stat_ptr, 0o100000 | 0o644, stable_ino(&path), size, blocks_for_size(size));
    }
    if let Some(process::FileDescriptor::Ext4 { ino, .. }) = process::get_fd(fd) {
        if let Some(root) = process::current_root::<A>() {
            if let Ok(inode) = root.stat(ino) {
                return write_stat(
                    memory,
                    stat_ptr,
                    inode.i_mode as u32,
                    ino as u64,
                    inode.i_size,
                    inode.i_blocks,
                );
            }
        }
    }
    write_stat(memory, stat_ptr, 0o100000 | 0o644, fd as u64, 0, 0)
}

pub(super) fn write_stat_for_path<A: KernelArch + 'static>(
    memory: &crate::user_paging::UserMemory,
    stat_ptr: usize,
    path: &str,
) -> SyscallOutcome {
    if let Some(cached) = stat_cache_get(path) {
        return write_stat(memory, stat_ptr, cached.mode, cached.ino, cached.size, cached.blocks);
    }
    if let Some(root) = process::current_root::<A>() {
        if let Ok(ino) = fs::resolve_path(root, path) {
            if let Ok(inode) = root.stat(ino) {
                let mode = inode.i_mode as u32;
                let size = inode.i_size;
                let blocks = inode.i_blocks;
                stat_cache_put(path, mode, ino as u64, size, blocks);
                return write_stat(memory, stat_ptr, mode, ino as u64, size, blocks);
            }
        }
    }
    if let Some(id) = memory_file_id(path) {
        let size = memory_file_len(id).unwrap_or(0) as u64;
        return write_stat(memory, stat_ptr, 0o100000 | 0o644, stable_ino(path), size, blocks_for_size(size));
    }
    let is_current_dir = process::current_cwd().as_deref() == Some(path);
    if directory_exists::<A>(path) || path == "/" || is_current_dir {
        return write_stat(memory, stat_ptr, 0o040000 | 0o755, stable_ino(path), 4096, 8);
    }
    SyscallOutcome::Return(ENOENT)
}

fn write_stat(
    memory: &crate::user_paging::UserMemory,
    stat_ptr: usize,
    mode: u32,
    ino: u64,
    size: u64,
    blocks: u64,
) -> SyscallOutcome {
    let mut stat = [0u8; 128];
    stat[8..16].copy_from_slice(&ino.to_le_bytes());
    stat[16..20].copy_from_slice(&mode.to_le_bytes());
    stat[20..24].copy_from_slice(&1u32.to_le_bytes());
    stat[48..56].copy_from_slice(&size.to_le_bytes());
    stat[56..60].copy_from_slice(&4096u32.to_le_bytes());
    stat[64..72].copy_from_slice(&blocks.to_le_bytes());
    if memory.write_user_bytes(stat_ptr, &stat).is_err() {
        return SyscallOutcome::Return(ENOSYS);
    }
    SyscallOutcome::Return(0)
}

fn blocks_for_size(size: u64) -> u64 {
    if size == 0 { 0 } else { size.div_ceil(512) }
}

fn stable_ino(path: &str) -> u64 {
    let mut hash = 5381u64;
    for byte in path.bytes() {
        hash = hash.wrapping_mul(33).wrapping_add(byte as u64);
    }
    hash.max(1)
}

fn stat_cache_get(path: &str) -> Option<StatCacheEntry> {
    unsafe {
        let entries = &*STAT_CACHE.inner.get();
        entries.iter().find(|entry| entry.path == path).cloned()
    }
}

fn stat_cache_put(path: &str, mode: u32, ino: u64, size: u64, blocks: u64) {
    unsafe {
        let entries = &mut *STAT_CACHE.inner.get();
        if entries.iter().any(|entry| entry.path == path) {
            return;
        }
        if entries.len() >= 8192 {
            entries.remove(0);
        }
        entries.push(StatCacheEntry {
            path: String::from(path),
            mode,
            ino,
            size,
            blocks,
        });
    }
}

