            // c_iflag(4) c_oflag(4) c_cflag(4) c_lflag(4) c_line(1) c_cc(19) = 36
            let mut termios = [0u8; 36];
            // c_iflag: ICRNL(0x100) | IXON(0x400) = 0x500
            termios[0..4].copy_from_slice(&0x500u32.to_le_bytes());
            // c_oflag: OPOST(0x1) | ONLCR(0x4) = 0x5
            termios[4..8].copy_from_slice(&0x5u32.to_le_bytes());
            // c_cflag: CREAD(0x80) | CS8(0x30) | B38400(0x11... actually on riscv B38400=0xF)
            // Use standard values: B115200=0x1002, CS8=0x30, CREAD=0x80, CLOCAL=0x800
            termios[8..12].copy_from_slice(&0x8bfu32.to_le_bytes());
            // c_lflag: ISIG(0x1) | ICANON(0x2) | ECHO(0x8) | ECHOE(0x10) | ECHOK(0x20)
            termios[12..16].copy_from_slice(&0x3bu32.to_le_bytes());
            // c_line: N_TTY(0)
            termios[16] = 0;
            // c_cc: set VEOF(4)=0x04, VEOL(5)=0xff, VERASE(2)=0x7f, VINTR(0)=0x03, VKILL(3)=0x15, VMIN(6)=1, VQUIT(1)=0x1c, VSTART(8)=0x11, VSTOP(9)=0x13, VSUSP(10)=0x1a, VTIME(5)=0
            // indices: 0=INTR, 1=QUIT, 2=ERASE, 3=KILL, 4=EOF, 5=VEOL, 6=VMIN, 7=VTIME, ...
            termios[17] = 0x03;  // VINTR = ^C
            termios[18] = 0x1c;  // VQUIT = ^\
            termios[19] = 0x7f;  // VERASE = DEL
            termios[20] = 0x15;  // VKILL = ^U
            termios[21] = 0x04;  // VEOF = ^D
            termios[22] = 0xff;  // VEOL
            termios[23] = 0x01;  // VMIN
            termios[24] = 0x00;  // VTIME
            // remaining c_cc entries stay 0
            if memory.write_user_bytes(arg, &termios).is_err() {
                return SyscallOutcome::Return(-14); // EFAULT
            }
            return SyscallOutcome::Return(0);
        }
    }
    // 其他 ioctl：返回 0 假装成功
    // 包括 TCSETS/TCSETSW/TCSETSF 等终端配置 ioctl，
    // 以及 FIONREAD/TIOCGWINSZ 等查询 ioctl
    SyscallOutcome::Return(0)
}

pub(super) fn sys_nanosleep<A: KernelArch>(req_ptr: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let Ok(req_bytes) = memory.read_user_bytes(req_ptr, 16) else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let tv_sec = u64::from_le_bytes(req_bytes[0..8].try_into().unwrap_or([0; 8]));
    let tv_nsec = u64::from_le_bytes(req_bytes[8..16].try_into().unwrap_or([0; 8]));
    let duration_ns = tv_sec.saturating_mul(1_000_000_000).saturating_add(tv_nsec);
    if duration_ns == 0 {
        return SyscallOutcome::Return(0);
    }
    let deadline = A::monotonic_time_nanos().saturating_add(duration_ns);
    // 忙等实现：轮询直到时间到
    while A::monotonic_time_nanos() < deadline {
        core::hint::spin_loop();
    }
    SyscallOutcome::Return(0)
}

pub(super) fn sys_times<A: KernelArch>(user_buf: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let mut tms = [0u8; 32];
    let ticks = crate::async_rt::current_tick();
    tms[0..8].copy_from_slice(&ticks.to_le_bytes());
    if memory.write_user_bytes(user_buf, &tms).is_err() {
        return SyscallOutcome::Return(ENOSYS);
    }
    SyscallOutcome::Return(ticks as isize)
}

pub(super) fn sys_clock_gettime<A: KernelArch>(user_buf: usize) -> SyscallOutcome {
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let now = A::monotonic_time_nanos();
    let mut timespec = [0u8; 16];
    timespec[0..8].copy_from_slice(&(now / 1_000_000_000).to_le_bytes());
    timespec[8..16].copy_from_slice(&(now % 1_000_000_000).to_le_bytes());
    if memory.write_user_bytes(user_buf, &timespec).is_err() {
        return SyscallOutcome::Return(ENOSYS);
    }
    SyscallOutcome::Return(0)
}

pub(super) fn sys_gettimeofday<A: KernelArch>(user_buf: usize) -> SyscallOutcome {
    if user_buf == 0 {
        return SyscallOutcome::Return(0);
    }
    let Some(memory) = process::current_user_memory() else {
        return SyscallOutcome::Return(ENOSYS);
    };
    let now = A::monotonic_time_nanos();
    let mut timeval = [0u8; 16];
    timeval[0..8].copy_from_slice(&(now / 1_000_000_000).to_le_bytes());
    timeval[8..16].copy_from_slice(&((now % 1_000_000_000) / 1_000).to_le_bytes());
    if memory.write_user_bytes(user_buf, &timeval).is_err() {
        return SyscallOutcome::Return(ENOSYS);
    }
    SyscallOutcome::Return(0)
}

