const FDT_MAGIC: u32 = 0xd00d_feed;
const FDT_BEGIN_NODE: u32 = 1;
const FDT_END_NODE: u32 = 2;
const FDT_PROP: u32 = 3;
const FDT_NOP: u32 = 4;
const FDT_END: u32 = 9;

#[derive(Clone, Copy)]
struct FdtHeader {
    totalsize: usize,
    off_dt_struct: usize,
    off_dt_strings: usize,
    off_mem_rsvmap: usize,
    size_dt_strings: usize,
    size_dt_struct: usize,
}

pub fn discover_memory(boot_info: &mut BootInfo) -> bool {
    let Some(header) = read_header(boot_info.fdt_addr) else {
        return false;
    };

    // DTB 本体也占用物理内存。先登记为 Bootloader，后面 MemoryMap 会从 usable 里扣掉。
    boot_info.add_memory_region(
        boot_info.fdt_addr as u64,
        header.totalsize as u64,
        BootMemoryKind::Bootloader,
    );
    parse_reserved_regions(boot_info, header);
    parse_memory_nodes(boot_info, header)
}

fn read_header(base: usize) -> Option<FdtHeader> {
    if base == 0 {
        return None;
    }

    let magic = read_be_u32(base)?;
    if magic != FDT_MAGIC {
        return None;
    }

    Some(FdtHeader {
        totalsize: read_be_u32(base + 4)? as usize,
        off_dt_struct: read_be_u32(base + 8)? as usize,
        off_dt_strings: read_be_u32(base + 12)? as usize,
        off_mem_rsvmap: read_be_u32(base + 16)? as usize,
        size_dt_strings: read_be_u32(base + 32)? as usize,
        size_dt_struct: read_be_u32(base + 36)? as usize,
    })
}

fn parse_reserved_regions(boot_info: &mut BootInfo, header: FdtHeader) {
    let mut cursor = boot_info.fdt_addr + header.off_mem_rsvmap;
    let end = boot_info.fdt_addr + header.totalsize;

    // mem_rsvmap 是 header 后面的固定表，每项两个 big-endian u64：
    // address/size，直到遇到全 0 结束。
    while cursor + 16 <= end {
        let Some(address) = read_be_u64(cursor) else {
            break;
        };
        let Some(size) = read_be_u64(cursor + 8) else {
            break;
        };
        cursor += 16;

        if address == 0 && size == 0 {
            break;
        }

        boot_info.add_memory_region(address, size, BootMemoryKind::Reserved);
    }
}

fn parse_memory_nodes(boot_info: &mut BootInfo, header: FdtHeader) -> bool {
    let struct_start = boot_info.fdt_addr + header.off_dt_struct;
    let struct_end = struct_start + header.size_dt_struct;
    let strings_start = boot_info.fdt_addr + header.off_dt_strings;
    let strings_end = strings_start + header.size_dt_strings;
    let mut cursor = struct_start;
    let mut depth = 0usize;
    let mut address_cells = 2usize;
    let mut size_cells = 2usize;
    let mut node_address_cells = [2usize; 16];
    let mut node_size_cells = [2usize; 16];
    let mut current_is_memory = false;
    let mut found = false;

    // FDT structure block 是 token stream，不是普通树结构。
    // 这里只实现当前需要的子集：跟踪 #address-cells/#size-cells，
    // 找 memory 节点的 reg 属性并转成 BootMemoryKind::Usable。
    while cursor + 4 <= struct_end {
        let Some(token) = read_be_u32(cursor) else {
            break;
        };
        cursor += 4;

        match token {
            FDT_BEGIN_NODE => {
                let name_start = cursor;
                while cursor < struct_end && read_u8(cursor) != Some(0) {
                    cursor += 1;
                }
                if cursor >= struct_end {
                    break;
                }

                current_is_memory = node_name_matches(name_start, b"memory");
                cursor += 1;
                cursor = align_up(cursor, 4);

                // cells 设置会被子节点继承。这里保存进入当前 depth 前的值，
                // 离开节点时再恢复父节点设置。
                if depth < node_address_cells.len() {
                    node_address_cells[depth] = address_cells;
                    node_size_cells[depth] = size_cells;
                }
                depth = depth.saturating_add(1);
            }
            FDT_END_NODE => {
                depth = depth.saturating_sub(1);
                if depth < node_address_cells.len() {
                    address_cells = node_address_cells[depth];
                    size_cells = node_size_cells[depth];
                }
                current_is_memory = false;
            }
            FDT_PROP => {
                if cursor + 8 > struct_end {
                    break;
                }
                let Some(len) = read_be_u32(cursor).map(|value| value as usize) else {
                    break;
                };
                let Some(nameoff) = read_be_u32(cursor + 4).map(|value| value as usize) else {
                    break;
                };
                cursor += 8;
                if cursor + len > struct_end {
                    break;
                }

                if string_eq(strings_start, strings_end, nameoff, b"#address-cells") {
                    if let Some(value) = read_cells(cursor, 1) {
                        address_cells = value as usize;
                    }
                } else if string_eq(strings_start, strings_end, nameoff, b"#size-cells") {
                    if let Some(value) = read_cells(cursor, 1) {
                        size_cells = value as usize;
                    }
                } else if current_is_memory
                    && string_eq(strings_start, strings_end, nameoff, b"reg")
                {
                    found |= parse_reg(boot_info, cursor, len, address_cells, size_cells);
                }

                cursor = align_up(cursor + len, 4);
            }
            FDT_NOP => {}
            FDT_END => break,
            _ => break,
        }
    }

    found
}

fn parse_reg(
    boot_info: &mut BootInfo,
    mut cursor: usize,
    len: usize,
    address_cells: usize,
    size_cells: usize,
) -> bool {
    let entry_cells = address_cells + size_cells;
    if entry_cells == 0 {
        return false;
    }

    let end = cursor + len;
    let entry_bytes = entry_cells * 4;
    let mut found = false;

    // reg = <addr size addr size ...>，addr/size 各自占 address_cells/size_cells 个 u32。
    while cursor + entry_bytes <= end {
        let Some(address) = read_cells(cursor, address_cells) else {
            break;
        };
        cursor += address_cells * 4;
        let Some(size) = read_cells(cursor, size_cells) else {
            break;
        };
        cursor += size_cells * 4;

        if boot_info.add_memory_region(address, size, BootMemoryKind::Usable) {
            found = true;
        }
    }

    found
}

fn read_cells(mut cursor: usize, cells: usize) -> Option<u64> {
    if cells > 2 {
        return None;
    }

    let mut value = 0u64;
    for _ in 0..cells {
        value = (value << 32) | read_be_u32(cursor)? as u64;
        cursor += 4;
    }
    Some(value)
}

fn string_eq(strings_start: usize, strings_end: usize, nameoff: usize, expected: &[u8]) -> bool {
    let mut cursor = strings_start + nameoff;
    for byte in expected {
        if cursor >= strings_end || read_u8(cursor) != Some(*byte) {
            return false;
        }
        cursor += 1;
    }
    cursor < strings_end && read_u8(cursor) == Some(0)
}

fn node_name_matches(name_start: usize, expected_prefix: &[u8]) -> bool {
    let mut cursor = name_start;
    for byte in expected_prefix {
        if read_u8(cursor) != Some(*byte) {
            return false;
        }
        cursor += 1;
    }

    matches!(read_u8(cursor), Some(0 | b'@'))
}

#[inline]
fn read_be_u64(addr: usize) -> Option<u64> {
    Some(((read_be_u32(addr)? as u64) << 32) | read_be_u32(addr + 4)? as u64)
}

#[inline]
fn read_be_u32(addr: usize) -> Option<u32> {
    Some(u32::from_be_bytes([
        read_u8(addr)?,
        read_u8(addr + 1)?,
        read_u8(addr + 2)?,
        read_u8(addr + 3)?,
    ]))
}

#[inline]
fn read_u8(addr: usize) -> Option<u8> {
    if addr == 0 {
        return None;
    }
    Some(unsafe { core::ptr::read_volatile(addr as *const u8) })
}

#[inline]
const fn align_up(value: usize, align: usize) -> usize {
    (value + align - 1) & !(align - 1)
}

use crate::BootInfo;

const EFI_SYSTEM_TABLE_SIGNATURE: u64 = 0x5453_5953_2049_4249;
const EFI_SYSTEM_TABLE_NR_TABLES_OFFSET: usize = 104;
const EFI_SYSTEM_TABLE_TABLES_OFFSET: usize = 112;
const EFI_CONFIG_TABLE_ENTRY_SIZE: usize = 24;

const DEVICE_TREE_GUID: [u8; 16] = [
    0xd5, 0x21, 0xb6, 0xb1, 0x9c, 0xf1, 0xa5, 0x41, 0x83, 0x0b, 0xd9, 0x15, 0x2c, 0x69, 0xaa, 0xe0,
];

pub fn discover_fdt(boot_info: &mut BootInfo) -> bool {
    let systab = boot_info.efi_system_table;
    if systab == 0 || read_u64(systab) != Some(EFI_SYSTEM_TABLE_SIGNATURE) {
        return false;
    }

    // 现在只从 EFI system table 的 configuration table 中找 DeviceTree GUID。
    // 后面接真机时，可以在同一层继续解析 EFI memory map 或 ACPI 表。
    let Some(nr_tables) = read_u64(systab + EFI_SYSTEM_TABLE_NR_TABLES_OFFSET) else {
        return false;
    };
    let Some(tables) =
        read_u64(systab + EFI_SYSTEM_TABLE_TABLES_OFFSET).map(|value| value as usize)
    else {
        return false;
    };

    // 早期保护一下循环上限，避免坏 firmware 填一个巨大 nr_tables 让我们扫出表外。
    for index in 0..core::cmp::min(nr_tables as usize, 32) {
        let entry = tables + index * EFI_CONFIG_TABLE_ENTRY_SIZE;
        if guid_eq(entry, &DEVICE_TREE_GUID) {
            let Some(fdt_addr) = read_u64(entry + 16).map(|value| value as usize) else {
                return false;
            };
            boot_info.fdt_addr = fdt_addr;
            return fdt_addr != 0;
        }
    }

    false
}

fn guid_eq(addr: usize, expected: &[u8; 16]) -> bool {
    for (offset, expected_byte) in expected.iter().enumerate() {
        if read_u8(addr + offset) != Some(*expected_byte) {
            return false;
        }
    }
    true
}

#[inline]
fn read_u64(addr: usize) -> Option<u64> {
    Some(u64::from_le_bytes([
        read_u8(addr)?,
        read_u8(addr + 1)?,
        read_u8(addr + 2)?,
        read_u8(addr + 3)?,
        read_u8(addr + 4)?,
        read_u8(addr + 5)?,
        read_u8(addr + 6)?,
        read_u8(addr + 7)?,
    ]))
}

#[inline]
fn read_u8(addr: usize) -> Option<u8> {
    if addr == 0 {
        return None;
    }
    Some(unsafe { core::ptr::read_volatile(addr as *const u8) })
}

