        )
    }

    fn rmdir(&mut self, parent: u32, name: &str) -> Result<()> {
        self.rmdir_inner(parent, name)
    }

    fn rename(&mut self, old_parent: u32, old_name: &str, new_parent: u32, new_name: &str) -> Result<()> {
        self.rename_inner(old_parent, old_name, new_parent, new_name)
    }

    fn truncate(&mut self, ino: u32, new_size: u64) -> Result<()> {
        self.truncate_inner(ino, new_size)
    }

    fn symlink(&mut self, parent: u32, name: &str, target: &str, uid: u32, gid: u32) -> Result<u32> {
        self.symlink_inner(parent, name, target, uid, gid)
    }

    fn readlink(&self, ino: u32) -> Result<String> {
        self.read_symlink(ino)
    }

    fn stat(&self, ino: u32) -> Result<Inode> {
        self.read_inode(ino)
    }

    fn chmod(&mut self, ino: u32, mode: u16) -> Result<()> {
        self.chmod_inner(ino, mode)
    }

    fn chown(&mut self, ino: u32, uid: u32, gid: u32) -> Result<()> {
        self.chown_inner(ino, uid, gid)
    }

    fn utimes(&mut self, ino: u32, atime: u32, mtime: u32) -> Result<()> {
        self.utimes_inner(ino, atime, mtime)
    }

    fn link(&mut self, parent: u32, name: &str, ino: u32) -> Result<()> {
        self.link_inner(parent, name, ino)
    }
}

use super::*;

pub(super) fn build_dirents<A: KernelArch + 'static>(path: &str) -> Vec<u8> {
    let mut out = Vec::new();
    append_dirent(&mut out, 1, ".", 4);
    append_dirent(&mut out, 1, "..", 4);
    if path == "/proc" {
        append_dirent(&mut out, 2, "mounts", 8);
        append_dirent(&mut out, 3, "self", 4);
        append_dirent(&mut out, 8, "meminfo", 8);
        return out;
    }
    if path == "/dev" {
        append_dirent(&mut out, 4, "null", 2);
        append_dirent(&mut out, 5, "rtc", 2);
        append_dirent(&mut out, 6, "misc", 4);
        return out;
    }
    if path == "/dev/misc" {
        append_dirent(&mut out, 7, "rtc", 2);
        return out;
    }
    if let Some(root) = process::current_root::<A>() {
        if let Ok(ino) = fs::resolve_path(root, path) {
            if let Ok(entries) = root.readdir(ino) {
                for entry in entries {
                    if !entry.is_unused() && !entry.is_dot_or_dotdot() {
                        append_dirent(
                            &mut out,
                            entry.inode as u64,
                            &entry.name,
                            dirent_type(entry.file_type),
                        );
                    }
                }
            }
        }
    }
    append_memory_dirents(path, &mut out);
    out
}

pub(super) fn append_memory_dirents(path: &str, out: &mut Vec<u8>) {
    let prefix = if path == "/" {
        String::from("/")
    } else {
        format_with_slash(path)
    };
    unsafe {
        let dirs = &*MEMORY_DIRS.inner.get();
        for (index, dir) in dirs.iter().enumerate() {
            if let Some(name) = immediate_child(&prefix, dir) {
                append_dirent(out, 0x1000 + index as u64, name, 4);
            }
        }
        let files = &*MEMORY_FILES.inner.get();
        for (index, file) in files.iter().enumerate() {
            if let Some(name) = immediate_child(&prefix, &file.path) {
                append_dirent(out, 0x2000 + index as u64, name, 8);
            }
        }
    }
}

pub(super) fn format_with_slash(path: &str) -> String {
    let mut value = String::from(path);
    if !value.ends_with('/') {
        value.push('/');
    }
    value
}

pub(super) fn immediate_child<'a>(prefix: &str, path: &'a str) -> Option<&'a str> {
    let rest = path.strip_prefix(prefix)?;
    if rest.is_empty() || rest.contains('/') {
        None
    } else {
        Some(rest)
    }
}

pub(super) fn dirent_type(file_type: luwu_ext4::layout::dir_entry::FileType) -> u8 {
    match file_type {
        luwu_ext4::layout::dir_entry::FileType::Directory => 4,
        luwu_ext4::layout::dir_entry::FileType::Symlink => 10,
        luwu_ext4::layout::dir_entry::FileType::CharDevice => 2,
        luwu_ext4::layout::dir_entry::FileType::BlockDevice => 6,
        _ => 8,
    }
}

pub(super) fn append_dirent(out: &mut Vec<u8>, ino: u64, name: &str, file_type: u8) {
    let reclen = (19 + name.len() + 1 + 7) & !7;
    let start = out.len();
    let next = start + reclen;
    out.resize(next, 0);
    out[start..start + 8].copy_from_slice(&ino.to_le_bytes());
    out[start + 8..start + 16].copy_from_slice(&(next as i64).to_le_bytes());
    out[start + 16..start + 18].copy_from_slice(&(reclen as u16).to_le_bytes());
    out[start + 18] = file_type;
    out[start + 19..start + 19 + name.len()].copy_from_slice(name.as_bytes());
}

